+        /// <param name="listOptions">Controls list generation behavior, including <see cref="ReportsListOptions.AddBlankPlaceholder"/> to insert a blank row at the top of the list and <see cref="ReportsListOptions.IncludeOnlyEnabledReports"/> to exclude disabled reports.</param>
+        public LookupList GetReportsForTableTypeList(IRequestedBy requestedBy, ReportsForTableTypeOptions options, ReportsListOptions listOptions = new ReportsListOptions())
+        {
+            var lookupList = new LookupList();
+            var reportCollection = GetReportsForTableType(requestedBy, options);
+
+           if (reportCollection == null)
+           {
+                return lookupList;
+           }
+
+            if (listOptions.AddBlankPlaceholder)
+            {
+                lookupList.Items.Add(new LookupListItem("", 0, LookupListItem.ValueTypes.Integer));
+            }
+
+            foreach (var report in reportCollection)
+            {
+
+                if (listOptions.IncludeOnlyEnabledReports && !report.IsEnabled)
+                {
+                    continue;
+                }
+
+                if (listOptions.ActualTableType != null && !report.OkToIncludeInPrintWizardReports(options.TableType, listOptions.ActualTableType.Value))
+                {
+                    continue;
+                }
+
+                if (listOptions.IsForMultipleRecords != null && ((listOptions.IsForMultipleRecords.Value && report.IsDefaultMultiple) || (!listOptions.IsForMultipleRecords.Value && report.IsDefaultSingle)))
+                {
+                    // Add the default report to the top of the list
+                    lookupList.Items.Insert(0, new LookupListItem(report.DisplayDescription, report.RecordId, LookupListItem.ValueTypes.Integer));
+                }
+                else
+                {
+                    lookupList.Items.Add(new LookupListItem(report.DisplayDescription, report.RecordId, LookupListItem.ValueTypes.Integer));
+                }
+            }//end of foreach report
+
+            return lookupList;
+        }
