+        /// <summary>
+        /// Returns default values for user-editable report wizard fields (filename, subject, body, optional
+        /// preloaded attachments/contacts). Report templates and ad hoc metadata are loaded via <c>GetComponentSettings</c>
+        /// (<see cref="ProjectSight.Common.Components.Web.ReportWizardConfig"/>). Table-level chrome flags are derived on the client.
+        /// </summary>
+        public async Task<ReportWizardInitData> GetReportWizardInitDataAsync(
+            IRequestedBy requestedBy,
+            PrologTable.Types tableType,
+            bool isForMultipleRecords,
+            int primaryKey,
+            ReportRequest.Behaviors behavior,
+            CancellationToken cancellationToken)
+        {
+            // Exceptions are handled by the caller
+
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                // --- Defaults ---
+                var request = new ReportRequest
+                {
+                    TableType = tableType,
+                    PrimaryKey = primaryKey,
+                    Behavior = behavior,
+                    RecordOption = isForMultipleRecords
+                        ? ReportRequest.RecordOptions.MultipleOneFileWithoutAttachments
+                        : ReportRequest.RecordOptions.Single
+                };
+
+                var forSingleRecord = !isForMultipleRecords;
+                var needsPreload = forSingleRecord && !ReportWizardInitDataRules.SkipsSingleRecordReportRequestPreload(tableType);
+
+                if (needsPreload)
+                {
+                    await CacheRecordForSingleReportRequestAsync(portfolioDB, request, cancellationToken);
+                    LoadDefaultReportContacts(portfolioDB, request);
+                    LoadDefaultReportAttachments(portfolioDB, request, portfolioDB.User);
+                }
+
+               
+                // --- Assemble result ---
+                var result = new ReportWizardInitData
+                {
+                    FileName = GetDefaultReportFileName(portfolioDB, request, forSingleRecord),
+                    Subject = GetDefaultReportSubject(portfolioDB, request),
+                    Body = GetDefaultReportBody(portfolioDB, request),
+                    Attachments = needsPreload ? request.Attachments : null,
+                    Contacts = needsPreload ? request.Contacts : null,
+                };
+
+                request.Record = null;
+
+                return result;
+            }
+        }
+
