+namespace ProjectSight.Common.Components
+{
+    /// <summary>
+    /// Table-type rules for report wizard <strong>server-side</strong> preload behavior only.
+    /// Wizard chrome (project selection, file library, attachments tab, PDF-by-table) is implemented in
+    /// TypeScript (<c>ps-ng/src/app/Reporting/dialog/utils/report-wizard-utils.ts</c>).
+    /// </summary>
+    public static class ReportWizardInitDataRules
+    {
+        /// <summary>
+        /// Table types that match legacy ReportingWizard behavior: single-record open does not preload
+        /// the row, default contacts/attachments from the record, or build a default file name from the
+        /// record summary (e.g. no matching <c>fn_enc_summary_*</c>). Add cases here when another table
+        /// type should follow the same pattern as <see cref="PrologTable.Types.UserGroup"/>.
+        /// </summary>
+        public static bool SkipsSingleRecordReportRequestPreload(PrologTable.Types tableType)
+        {
+            switch (tableType)
+            {
+                case PrologTable.Types.UserGroup:
+                    return true;
+
+                default:
+                    return false;
+            }
+        }
+    }
+}

