+
+/** Angular custom-element bridge for the page-level select-contact-popover (DEF host). */
+interface SelectContactPopoverNgElement extends HTMLElement {
+    ngElementStrategy?: {
+        componentRef?: {
+            instance?: SelectContactPopoverComponent;
+        };
+    };
+}

