+import { TestBed } from "@angular/core/testing";
+import { CommonModule } from "@angular/common";
+import { afterAll } from "vitest";
+import { GainsightIdDirective } from "shared/directives/gainsightId.directive";
+import { BaseGridComponent } from "shared/components/BaseGridComponent";
+import { ReportWizardGridComponent } from "./report-wizard-grid.component";
+
+type NgAfterViewInit = () => void;
+
+let savedLifecycle: {
+    baseAfterViewInit: NgAfterViewInit;
+    reportWizardAfterViewInit: NgAfterViewInit;
+} | null = null;
+
+/** Minimal template has no `#grid`; skip Ignite lifecycle that requires `IgxGridComponent`. */
+function patchReportWizardGridLifecycleForDomTests(): void {
+    if (savedLifecycle) {
+        return;
+    }
+
+    const baseAfterViewInit = BaseGridComponent.prototype.ngAfterViewInit;
+    const reportWizardAfterViewInit = ReportWizardGridComponent.prototype.ngAfterViewInit;
+
+    savedLifecycle = { baseAfterViewInit, reportWizardAfterViewInit };
+
+    BaseGridComponent.prototype.ngAfterViewInit = function (this: BaseGridComponent): void {
+        if (!this.grid) {
+            return;
+        }
+        baseAfterViewInit.call(this);
+    };
+
+    ReportWizardGridComponent.prototype.ngAfterViewInit = function (this: ReportWizardGridComponent): void {
+        if (!this.grid) {
+            return;
+        }
+        reportWizardAfterViewInit.call(this);
+    };
+
+    // One restore hook per spec file that first applies the patch (Vitest runs afterAll at file end).
+    afterAll(restoreReportWizardGridLifecyclePatches);
+}
+
+/** Restores prototype methods patched by {@link patchReportWizardGridLifecycleForDomTests}. */
+export function restoreReportWizardGridLifecyclePatches(): void {
+    if (!savedLifecycle) {
+        return;
+    }
+
+    BaseGridComponent.prototype.ngAfterViewInit = savedLifecycle.baseAfterViewInit;
+    ReportWizardGridComponent.prototype.ngAfterViewInit = savedLifecycle.reportWizardAfterViewInit;
+    savedLifecycle = null;
+}
+
+/**
+ * Ignite `igx-grid` pulls in IgxScrollInertiaDirective, which breaks under jsdom + Zone.js
+ * (AbortSignal / EventTarget). DOM/QA specs only need stable `data-gainsight` targets.
+ */
+export const REPORT_WIZARD_GRID_MINIMAL_TEST_TEMPLATE = `
+@if (isVisible()) {
+<div class="registered-grid-container" [gainsightId]="reportWizardGridQa.root">
+    <div [gainsightId]="reportWizardGridQa.grid"></div>
+    <div [gainsightId]="reportWizardGridQa.dragIcon"></div>
+    <div [gainsightId]="reportWizardGridQa.headSelector"></div>
+</div>
+}`;
+
+/** Call after `configureTestingModule` and before `compileComponents`. */
+export function overrideReportWizardGridForDomTests(testBed = TestBed): void {
+    patchReportWizardGridLifecycleForDomTests();
+    testBed.overrideComponent(ReportWizardGridComponent, {
+        set: {
+            template: REPORT_WIZARD_GRID_MINIMAL_TEST_TEMPLATE,
+            imports: [CommonModule, GainsightIdDirective],
+        },
+    });
+}

