+import {
+    ChangeDetectionStrategy,
+    Component,
+    ElementRef,
+    HostBinding,
+    HostListener,
+    Injector,
+    OnInit,
+    ViewChild,
+    computed,
+    inject,
+    input,
+    model,
+    signal,
+} from "@angular/core";
+import { toObservable } from "@angular/core/rxjs-interop";
+import { combineLatest } from "rxjs";
+import { filter } from "rxjs/operators";
+import { CommonModule } from "@angular/common";
+import { FormsModule } from "@angular/forms";
+import { BaseComponent } from "shared/components/BaseComponent";
+import { ProjectLite } from "Reporting/dialog/models/ProjectLite";
+import { ModusButtonComponent } from "shared/controls/modus-button/modus-button.component";
+import { GainsightIdDirective } from "shared/directives/gainsightId.directive";
+import { ModusTooltipDirective } from "shared/directives/modus-tooltip.directive";
+
