+import { ReportingOptions } from "./ReportingOptions";
+import { PrologTableTypes } from "shared/enums/PrologTableTypes";
+import { QueryStringParameterNames } from "shared/support/URLHelper";
+import { shouldShowProjectSelection } from "../utils/report-wizard-utils";
+
+export interface ReportWizardOpenParams {
+    tableType: PrologTableTypes;
+    isForMultipleRecords: boolean;
+    keyValues: string;
+    actualTableType: number;
+    showProjectSelection: boolean;
+    options: ReportingOptions;
+    callerProjectId?: number;
+}
+
+/**
+ * Parses the report wizard query string and assembles all parameters needed
+ * to open the dialog. Shared by both the Angular-direct path (ReportingWizardWindow)
+ * and the legacy iframe bridge (AppComponent).
+ *
+ * @param options A {@link ReportingOptions} instance. The legacy bridge (`CTICommon.js` `ReportingWizardWindow`) always
+ * provides this via `initializeReportingOptions` before `bridge.open` runs.
+ */
+export function buildReportWizardOpenParams(
+    queryString: string,
+    keyValues: string,
+    options: ReportingOptions,
+    fallbackTableType: number,
+    callerProjectId?: number
+): ReportWizardOpenParams {
+    const q = queryString?.trim() || "";
+    const normalized = q.startsWith("?") || q.startsWith("&") ? q.slice(1) : q;
+    const params = new URLSearchParams(normalized);
+
+    const tableType = parseInt(
+        params.get(QueryStringParameterNames.FromRecordType) ?? fallbackTableType.toString(), 10
+    ) || PrologTableTypes.None;
+    const isForMultipleRecords = params.has(QueryStringParameterNames.FromList);
+
+    if (!keyValues && isForMultipleRecords && options.PrintingVisibleItems) {
+        keyValues = "-1";
+    }
+    if (!keyValues && !isForMultipleRecords) {
+        keyValues = (params.get(QueryStringParameterNames.FromRecordKey) ?? "").toString();
+    }
+
+    const actualTableType = parseInt(params.get(QueryStringParameterNames.ChildRecordType) ?? "0", 10) || PrologTableTypes.None;
+
+    const behaviorParam = parseInt(params.get(QueryStringParameterNames.ReportWizardBehavior) ?? "0", 10) || 0;
+    if (behaviorParam) {
+        options.Behavior = behaviorParam;
+    }
+
+    const comids = params.get(QueryStringParameterNames.CompanyIDs) ?? "";
+    const locids = params.get(QueryStringParameterNames.LocationIDs) ?? "";
+    const filters: Record<string, string> = {};
+    if (comids) {
+        filters["@CompanyIDs"] = comids;
+    }
+    if (locids) {
+        filters["@LocationIDs"] = locids;
+    }
+    if (Object.keys(filters).length > 0) {
+        options.AdditionalDataFilters = filters;
+    }
+
+    const showProjectSelection = shouldShowProjectSelection(isForMultipleRecords, tableType, actualTableType)
+        && options.PrintingVisibleItems === true;
+
+    return {
+        tableType: tableType as PrologTableTypes,
+        isForMultipleRecords,
+        keyValues: keyValues ?? "",
+        actualTableType,
+        showProjectSelection,
+        options,
+        callerProjectId,
+    };
+}

