+import { Injector, NgZone } from "@angular/core";
+import { buildReportWizardOpenParams } from "Reporting/dialog/models/report-wizard-open-params";
+import { ReportWizardDialogService } from "Reporting/dialog/services/report-wizard-dialog.service";
+import { PrologTableTypes } from "shared/enums/PrologTableTypes";
+import { ReportingOptions } from "Reporting/dialog/models/ReportingOptions";
+import { ApplicationContextService } from "shared/services/ApplicationContextService";
+import { wemiExceptionService } from "shared/support/wemiExceptionService";
+import { PageTypes } from "shared/enums/PageConfiguration";
+
+/** FDEF page types that register in-page `<modal-host>` (see `fdef.bootstrap.ts`). */
+const FDEF_PAGE_TYPES_WITH_LOCAL_MODAL_HOST = new Set<PageTypes>([
+    PageTypes.MeetingMinutes,
+    PageTypes.Checklist,
+    PageTypes.Transmittal,
+    PageTypes.SubmittalPackage,
+    PageTypes.Drawing,
+    PageTypes.SpecSection,
+    PageTypes.SpecSet,
+]);
+
+export function fdefPageTypeHasLocalModalHost(pageType: PageTypes): boolean {
+    return FDEF_PAGE_TYPES_WITH_LOCAL_MODAL_HOST.has(pageType);
+}
+
+/**
+ * Installs `AngularReportingWizard` on {@link targetWindow} so legacy pages
+ * (CTICommon.js / DataViews.js / FormManagerEditor.js) can open the Angular report wizard.
+ *
+ * - **Shell** (`AppComponent`): pass `window.top` when `window === window.top`.
+ * - **FDEF iframe** (`fdef.bootstrap.ts`): pass `window` for page types with in-page `<modal-host>`
+ *   so the wizard uses that app's {@link ReportWizardDialogService} and {@link ModalHostService}.
+ *   Do not assign to `window.top` from an iframe — that would overwrite the shell bridge.
+ *
+ * Legacy entry: `CTICommon.js` `ReportingWizardWindow.openCommon` resolves
+ * `window.AngularReportingWizard` first, then `window.top.AngularReportingWizard`.
+ */
+export function installReportingWizardBridge(
+    targetWindow: Window,
+    ngZone: NgZone,
+    dialogService: ReportWizardDialogService,
+    injector: Injector
+): void {
+    const exceptionService = injector.get(wemiExceptionService);
+    const applicationContext = injector.get(ApplicationContextService);
+    const bridge = {
+        open(queryString: string, keyValues: string, opts: ReportingOptions, successCallback: () => void, callerProjectId?: number) {
+            ngZone.run(() => {
+                if (!applicationContext.injector) {
+                    exceptionService.logError("Reporting wizard bridge: no active application context (injector) available.", false);
+                    return;
+                }
+                if (opts == null) {
+                    exceptionService.logError(
+                        "Reporting wizard bridge: ReportingOptions (opts) is required. Legacy callers must set m_Options in CTICommon.js ReportingWizardWindow before openCommon.",
+                        false
+                    );
+                    return;
+                }
+                const openParams = buildReportWizardOpenParams(queryString, keyValues, opts, PrologTableTypes.None, callerProjectId);
+                dialogService
+                    .open(
+                        openParams.keyValues,
+                        openParams.options,
+                        openParams.tableType,
+                        openParams.isForMultipleRecords,
+                        openParams.actualTableType,
+                        openParams.showProjectSelection,
+                        openParams.callerProjectId
+                    )
+                    .then((result) => {
+                        if (result === true && successCallback) {
+                            successCallback();
+                        }
+                    })
+                    .catch((ex: unknown) => {
+                        if (ex instanceof Error) {
+                            exceptionService.logException(ex);
+                        } else {
+                            exceptionService.logError(`Reporting wizard bridge error: ${String(ex)}`, false);
+                        }
+                    });
+            });
+        }
+    };
+
+    try {
+        targetWindow["AngularReportingWizard"] = bridge;
+    } catch { /* cross-origin */ }
+}
