+        if (state.behavior === REPORT_BEHAVIORS.None && state.selectedProjectIds?.length) {
+            request.AdditionalProjectIds = state.selectedProjectIds;
+            if (state.options?.filters?.length) {
+                request.AdditionalProjectFilters = state.options.filters as never;
+            }
+        }
