+    /**
+     * Flattens To/Cc/Bcc rows into report-request contacts with EmailType set per bucket.
+     * Used when assembling {@link ReportRequest.Contacts} (via panel service request/response).
+     */
+    buildEmailContactsForReportRequest(
+        tos: ContactForPicklist[],
+        ccs: ContactForPicklist[],
+        bccs: ContactForPicklist[],
+    ): ContactForPicklist[] {
+        const selectedContacts: ContactForPicklist[] = [];
+        const buckets: [ContactForPicklist[], EMailTypes][] = [
+            [tos, EMailTypes.To],
+            [ccs, EMailTypes.CC],
+            [bccs, EMailTypes.BCC],
+        ];
