+    /**
+     * Validates state and contacts. Returns error message or null if valid.
+     */
+    validateBeforeInitiate(
+        state: ReportActionState,
+        action: ReportActionValue,
+        nomenclature: ReportWizardNomenclature,
+        validateContacts: () => boolean
+    ): string | null {
+        if (!state.isAdHocReport && state.behavior !== REPORT_BEHAVIORS.MeetingSendInvitation && !state.reportId) {
+            return nomenclature.mustSelectReport;
+        }
+        if (action === REPORT_ACTION.Email && !validateContacts()) {
+            return nomenclature.oneRecipientRequired;
+        }
+        return null;
+    }
+
+    private getVisibleAdHocColumns(columns: any[], defaultGroup: string, defaultSort: string, fromAngular: boolean): any[] {
+        const adHocColumns: any[] = [];
+        for (let i = 0; i < columns.length; i++) {
+            const column = columns[i];
+
+            if (column.behavior === ListViewColumnBehaviors.FileIcon) {
+                continue;
+            }
+
+            let okToAdd = false;
+            if (fromAngular) {
+                okToAdd = !column.hidden && (column.width !== 0 || column.columnName === defaultGroup || column.columnName === defaultSort);
+            } else {
+                okToAdd = column.Width !== 0 || column.ColumnName === defaultGroup || column.ColumnName === defaultSort;
+            }
