+    /**
+     * Initiates the report request.
+     *
+     * For email actions: sums {@link IncludeAsTypes.Attachment} and {@link IncludeAsTypes.EmbedInReport}
+     * attachment sizes toward the email payload budget; {@link IncludeAsTypes.Link} rows do not count.
+     * If the total exceeds {@link FILES_TOO_LARGE_MB} and the user confirms, those Attachment/Embed rows
+     * are rewritten in-place to {@link IncludeAsTypes.Link} so the server emails links instead of embedding bytes.
+     */
+    async initiateReport(
+        request: ReportRequest,
+        action: ReportActionValue,
+        nomenclature: ReportWizardNomenclature,
+        onClose: () => void,
+        state: ReportActionState
+    ): Promise<void> {
+        if (action === REPORT_ACTION.Email && request.Attachments?.length) {
+            const attachments = request.Attachments as { IncludeAs?: number; FileSize?: number }[];
+            const sizeMb = attachments.reduce((sum: number, attachment) => {
+                if (attachment.IncludeAs === IncludeAsTypes.Attachment || attachment.IncludeAs === IncludeAsTypes.EmbedInReport) {
+                    return sum + (attachment.FileSize ?? 0);
+                }
+                return sum;
+            }, 0) / 1048576;
+
+            if (sizeMb > FILES_TOO_LARGE_MB) {
+                const doInitiate = await this.wemiConfirmAsync({
+                    content: nomenclature.filesTooLargeMessage,
+                    confirmText: nomenclature.filesTooLargeSendButton,
+                    cancelText: nomenclature.filesTooLargeCancelButton,
+                });
+                if (!doInitiate) {
+                    return;
+                }
+
+                attachments.forEach((attachment) => {
+                    if (attachment.IncludeAs === IncludeAsTypes.Attachment || attachment.IncludeAs === IncludeAsTypes.EmbedInReport) {
+                        attachment.IncludeAs = IncludeAsTypes.Link;
+                    }
+                });
+            }
+        }
+
+        if (
+            action === REPORT_ACTION.FileLibrary &&
+            request.AdditionalProjectIds?.length &&
+            nomenclature.multiProjectFileLibraryTitle
+        ) {
+            const doInitiate = await this.wemiConfirmAsync({
+                title: nomenclature.multiProjectFileLibraryTitle,
+                content: nomenclature.multiProjectFileLibraryText,
+                confirmText: nomenclature.multiProjectFileLibraryYes,
+                cancelText: nomenclature.multiProjectFileLibraryNo,
+                defaultButton: PromptButtonTypes.Cancel,
+            });
+            if (!doInitiate) {
+                return;
+            }
+        }
+
+        try {
+            const fileRequestId = await this._reportSystem.InitiateReportRequest(request);
+
+            const downloadAction =
+                action === REPORT_ACTION.View
+                    ? DownloadModuleActionTypes.View
+                    : action === REPORT_ACTION.FileLibrary
+                      ? (state.isForMultipleRecords ? DownloadModuleActionTypes.Download : DownloadModuleActionTypes.View)
+                      : DownloadModuleActionTypes.Download;
