+function makeContact(over: Partial<ContactForPicklist> = {}): ContactForPicklist {
+    const c = new ContactForPicklist();
+    c.DisplayName = "Jane Doe";
+    c.Email = "jane@example.com";
+    c.Title = "";
+    c.ContactID = 1;
+    c.CompanyName = "";
+    c.CompanyID = 0;
+    c.UserID = "";
+    c.UserDeleted = false;
+    c.ContactPicture = "";
+    c.EmailType = EMailTypes.To;
+    c.DisplayAddress = "";
+    c.Tel = "";
+    c.Cel = "";
+    Object.assign(c, over);
+    return c;
+}
+
+/**
+ * Characterization tests for ContactInputComponent.
+ * Template is stubbed (`configureStandalonePageTest` default); see angular-unit-testing.md.
+ */
+describe("ContactInputComponent", () => {
+    let fixture: ComponentFixture<ContactInputComponent>;
+    let component: ContactInputComponent;
+
+    async function setup(): Promise<void> {
+        const result = await configureStandalonePageTest(ContactInputComponent, {});
+        fixture = result.fixture;
+        component = result.component;
+        fixture.detectChanges();
+    }
+
+    beforeEach(() => {
+        vi.useFakeTimers({ shouldAdvanceTime: true });
+    });
+
+    afterEach(() => {
+        vi.useRealTimers();
+    });
+
+    describe("Business Logic", () => {
+        /** Invokes private {@link ContactInputComponent.applyFilter}. */
+        function applyFilter(query: string): void {
+            component["applyFilter"](query);
+        }
+
+        it("should create", async () => {
+            await setup();
+            expect(component).toBeTruthy();
+        });
+
+        describe("applyFilter", () => {
+            beforeEach(async () => {
+                await setup();
+            });
+
+            it("includes all non-selected contacts when query is empty", () => {
+                const a = makeContact({ ContactID: 1, DisplayName: "A" });
+                const b = makeContact({ ContactID: 2, DisplayName: "B" });
+                fixture.componentRef.setInput("contacts", [a, b]);
+                component.selected.set([]);
+                applyFilter("");
+                expect(component.filteredContacts().map((c) => c.ContactID).sort()).toEqual([1, 2]);
+            });
+
+            it("excludes contacts already in selected", () => {
