+import {
+    ChangeDetectionStrategy,
+    Component,
+    ElementRef,
+    input,
+    model,
+    OnInit,
+    output,
+    signal,
+    ViewChild,
+} from "@angular/core";
+import { CommonModule } from "@angular/common";
+import { Subject } from "rxjs";
+import { debounceTime } from "rxjs/operators";
+import { ContactForPicklist } from "shared/classes/Lookups/ContactForPicklist";
+import { BaseComponent } from "shared/components/BaseComponent";
+import { ModusButtonComponent } from "shared/controls/modus-button/modus-button.component";
+import { ModusChipComponent } from "shared/controls/modus-chip/modus-chip.component";
+import { GainsightIdDirective } from "shared/directives/gainsightId.directive";
+import { ModusTooltipDirective } from "shared/directives/modus-tooltip.directive";
+import { CONTACT_INPUT_QA } from "./contact-input-qa";
+
+/**
+ * Multi-select contact picker (chip field + inline filter list).
+ * Renders selected contacts as modus-chip tokens, provides a text input for
+ * searching/filtering, and shows an inline dropdown of matching contacts.
+ * Chevron (inside the field) toggles that list; the search icon emits
+ * searchIconClicked for a parent-driven contact picker (e.g. popover).
+ * Extends {@link BaseComponent} for `subscribeTo()` teardown only; the parent
+ * (EmailSelectorComponent) owns contact data and API calls.
+ */
+@Component({
+    selector: "contact-input",
+    templateUrl: "./contact-input.component.html",
+    styleUrls: ["./contact-input.component.css"],
+    standalone: true,
+    imports: [
+        CommonModule,
+        GainsightIdDirective,
+        ModusChipComponent,
+        ModusButtonComponent,
+        ModusTooltipDirective,
+    ],
+    changeDetection: ChangeDetectionStrategy.OnPush,
+})
+export class ContactInputComponent extends BaseComponent implements OnInit {
+    /** Full list of available contacts to search through */
+    public readonly contacts = input<ContactForPicklist[]>([]);
+
+    /** Two-way bound list of currently selected contacts */
+    public readonly selected = model<ContactForPicklist[]>([]);
+
+    /** Placeholder shown when no contacts are selected */
+    public readonly placeholder = input("");
+
+    /** Tooltip for the search/magnifier icon button */
+    public readonly tooltip = input("");
+
+    /** Emitted when the magnifier is activated; payload is the inner native button (popover anchor). */
+    public readonly searchIconClicked = output<HTMLElement>();
+
+    public ngOnInit(): void {
+        this.subscribeTo(
+            this._queryChange$.pipe(debounceTime(200)),
+            (q) => this.applyFilter(q)
+        );
+    }
+
+    /** Stable Gainsight / test ids for the template (shared with `contact-input-qa.ts`). */
+    protected readonly contactInputQa = CONTACT_INPUT_QA;
+
+    protected readonly query = signal("");
+    protected readonly showDropdown = signal(false);
+    protected readonly filteredContacts = signal<ContactForPicklist[]>([]);
+
+    protected onSearchInput(event: Event): void {
+        const value = (event.target as HTMLInputElement).value;
+        this.query.set(value);
+        this.onQueryChange(value);
+    }
+
+    protected onQueryChange(q: string): void {
+        this._queryChange$.next(q);
+    }
+
+    protected onFocus(): void {
+        this.applyFilter(this.query());
+        this.showDropdown.set(true);
+    }
+
+    protected onBlur(): void {
+        // Delay so mousedown on a dropdown item fires before blur hides the list
+        setTimeout(() => this.showDropdown.set(false), 150);
+    }
+
+    protected focusInput(): void {
+        this._inputEl?.nativeElement.focus();
+    }
+
+    protected selectContact(contact: ContactForPicklist): void {
+        this.selected.update((prev) => [...prev, contact]);
+        this.query.set("");
+        this.filteredContacts.set([]);
+        this.showDropdown.set(false);
+        setTimeout(() => this._inputEl?.nativeElement.focus());
+    }
+
+    protected removeContact(contact: ContactForPicklist): void {
+        this.selected.update((prev) =>
+            prev.filter((c) => c.ContactID !== contact.ContactID)
+        );
+    }
+
+    protected onSearchMouseDown(event: MouseEvent): void {
+        event.preventDefault();
+        event.stopPropagation();
+        this.showDropdown.set(false);
+    }
+
+    protected onSearchClick(): void {
+        this.showDropdown.set(false);
+        const el = this._searchActionBtn?.element?.nativeElement as HTMLElement | undefined;
+        if (el) {
+            this.searchIconClicked.emit(el);
+        }
+    }
+
+    protected onChevronMouseDown(event: MouseEvent): void {
+        event.preventDefault();
+    }
+
+    protected onChevronToggle(): void {
+        const wasOpen = this.showDropdown();
+        this.applyFilter(this.query());
+        const hasResults = this.filteredContacts().length > 0;
+        if (!hasResults) {
+            this.showDropdown.set(false);
+            return;
+        }
+        this.showDropdown.set(wasOpen ? false : true);
+        setTimeout(() => this._inputEl?.nativeElement.focus());
+    }
+
+    private readonly _queryChange$ = new Subject<string>();
+
+    private _inputEl: ElementRef<HTMLInputElement>;
+
+    @ViewChild("searchInput")
+    private set searchInputSetter(value: ElementRef<HTMLInputElement>) {
+        if (value) {
+            this._inputEl = value;
+        }
+    }
+
+    @ViewChild("searchActionBtn")
+    private readonly _searchActionBtn?: ModusButtonComponent;
+
+    private applyFilter(query: string): void {
+        const q = query.toLowerCase().trim();
+        const selectedIds = new Set(this.selected().map((c) => c.ContactID));
+        const results = this.contacts().filter((c) => {
+            if (selectedIds.has(c.ContactID)) {
+                return false;
+            }
+            if (!q) {
+                return true;
+            }
+            return (
+                c.DisplayName?.toLowerCase().includes(q) ||
+                c.Email?.toLowerCase().includes(q)
+            );
+        });
+        this.filteredContacts.set(results.slice(0, 50));
+        this.showDropdown.set(results.length > 0);
+    }
+}

