+using System.Collections.Generic;
+
+namespace ProjectSight.Common.Components
+{
+    /// <summary>
+    /// One report template row returned for the print/report wizard list (subset of <see cref="Report"/> fields).
+    /// </summary>
+    public sealed class ReportWizardInitReportItem
+    {
+        public int RecordId { get; set; }
+
+        public string DisplayDescription { get; set; }
+
+        public bool PDFOutputOnly { get; set; }
+
+        public bool IsDefaultSingle { get; set; }
+
+        public bool IsDefaultMultiple { get; set; }
+
+        /// <summary>
+        /// The actual table type for this report.
+        /// This is used in very specific cases where the table type for a report is different than the table type that it is maintained in.
+        /// The only current example is BudgetSnapshotItems reports which are maintained in the Budget settings because the two tables have an identical structure.
+        /// </summary>
+        public PrologTable.Types ActualTableType { get; set; }
+    }
+
+    /// <summary>
+    /// Payload for <c>GetReportWizardInitData</c>: default filename/subject/body and optional preloaded attachments/contacts.
+    /// Report templates and ad hoc list metadata are supplied by <c>GetComponentSettings</c> (<see cref="ProjectSight.Common.Components.Web.ReportWizardConfig"/>).
+    /// Table-level wizard chrome (project selection, file library section, attachments tab, PDF-by-table) is derived on the client
+    /// (TypeScript <c>report-wizard-utils.ts</c>, aligned with legacy ReportingWizard behavior). Single-record preload skipping remains server-side in
+    /// <see cref="ReportWizardInitDataRules"/>.
+    /// </summary>
+    public sealed class ReportWizardInitData
+    {
+        public string FileName { get; set; }
+
+        public string Subject { get; set; }
+
+        public string Body { get; set; }
+
+        public ReportRequestAttachmentCollection Attachments { get; set; }
+        public ContactForPicklistCollection Contacts { get; set; }
+    }
+}
diff --git a/Core/Common/Components/Reports/ReportWizardInitDataRules.cs b/Core/Common/Components/Reports/ReportWizardInitDataRules.cs
new file mode 100644
index 00000000000..9d446b91ca5
--- /dev/null
+++ b/Core/Common/Components/Reports/ReportWizardInitDataRules.cs
@@ -0,0 +1,28 @@
+namespace ProjectSight.Common.Components
+{
+    /// <summary>
+    /// Table-type rules for report wizard <strong>server-side</strong> preload behavior only.
+    /// Wizard chrome (project selection, file library, attachments tab, PDF-by-table) is implemented in
+    /// TypeScript (<c>ps-ng/src/app/Reporting/dialog/utils/report-wizard-utils.ts</c>).
+    /// </summary>
+    public static class ReportWizardInitDataRules
+    {
+        /// <summary>
+        /// Table types that match legacy ReportingWizard behavior: single-record open does not preload
+        /// the row, default contacts/attachments from the record, or build a default file name from the
+        /// record summary (e.g. no matching <c>fn_enc_summary_*</c>). Add cases here when another table
+        /// type should follow the same pattern as <see cref="PrologTable.Types.UserGroup"/>.
+        /// </summary>
+        public static bool SkipsSingleRecordReportRequestPreload(PrologTable.Types tableType)
+        {
+            switch (tableType)
+            {
+                case PrologTable.Types.UserGroup:
+                    return true;
+
+                default:
+                    return false;
+            }
+        }
+    }
+}
