@@ -0,0 +1,46 @@
+using FluentAssertions;
+using Microsoft.VisualStudio.TestTools.UnitTesting;
+using ProjectSight.Common.Components;
+
+namespace ProjectSight.Tests.UnitTests.Reports
+{
+    /// <summary>
+    /// Characterization for <see cref="ReportWizardInitDataRules.SkipsSingleRecordReportRequestPreload"/> only.
+    /// Table-type chrome rules are covered by <c>report-wizard-utils.spec.ts</c> on the client.
+    /// </summary>
+    [TestClass]
+    public class ReportWizardInitDataRulesTests
+    {
+        #region SkipsSingleRecordReportRequestPreload — tables with no record-summary proc
+
+        [TestMethod]
+        public void SkipsSingleRecordReportRequestPreload_UserGroup_IsTrue()
+        {
+            ReportWizardInitDataRules.SkipsSingleRecordReportRequestPreload(PrologTable.Types.UserGroup)
+                .Should().BeTrue();
+        }
+
+        [TestMethod]
+        public void SkipsSingleRecordReportRequestPreload_RFI_IsFalse()
+        {
+            ReportWizardInitDataRules.SkipsSingleRecordReportRequestPreload(PrologTable.Types.RFI)
+                .Should().BeFalse();
+        }
+
+        [TestMethod]
+        public void SkipsSingleRecordReportRequestPreload_Drawing_IsFalse()
+        {
+            ReportWizardInitDataRules.SkipsSingleRecordReportRequestPreload(PrologTable.Types.Drawing)
+                .Should().BeFalse();
+        }
+
+        [TestMethod]
+        public void SkipsSingleRecordReportRequestPreload_None_IsFalse()
+        {
+            ReportWizardInitDataRules.SkipsSingleRecordReportRequestPreload(PrologTable.Types.None)
+                .Should().BeFalse();
+        }
+
+        #endregion
+    }
+}
