-        public static ReportCollection LoadReportsIntoCombo(igCombo cboReport, PrologTable.Types tableType, PageBase parentPage, bool isForMultipleRecords, bool doNotLimitDeniedReports = false, PrologTable.Types actualTableType = PrologTable.Types.None)
