+<div class="email-selector" [gainsightId]="emailSelectorQa.root">
+    @let nom = nomenclature();
+    <!-- To row -->
+    <div class="email-selector-label-row">
+        <span class="email-selector-label" [gainsightId]="emailSelectorQa.toLabel">{{ nom.typeTo }}</span>
+        <div class="email-selector-cc-bcc-links">
+            @if (!showCC()) {
+                <modus-button
+                    [variant]="'borderless'"
+                    [color]="'primary'"
+                    [size]="'sm'"
+                    [label]="nom.typeCC"
+                    [gainsightId]="emailSelectorQa.ccLink"
+                    (buttonClick)="showCC.set(true)"
+                ></modus-button>
+            }
+            @if (!showBCC()) {
+                <modus-button
+                    [variant]="'borderless'"
+                    [color]="'primary'"
+                    [size]="'sm'"
+                    [label]="nom.typeBCC"
+                    [gainsightId]="emailSelectorQa.bccLink"
+                    (buttonClick)="showBCC.set(true)"
+                ></modus-button>
+            }
+        </div>
+    </div>
+    <div [gainsightId]="emailSelectorQa.toInput">
+        <contact-input
+            [contacts]="contactsForPicklist()"
+            [(selected)]="tos"
+            [placeholder]="nom.enterContactNameOrEmail"
+            [tooltip]="nom.searchForContactsTooltip"
+            (searchIconClicked)="searchForContacts($event, eMailType.To)"
+        ></contact-input>
+    </div>
+
+    <!-- Cc row -->
+    @if (showCC()) {
+        <div class="email-selector-label-row email-selector-label-row-sub">
+            <span class="email-selector-label" [gainsightId]="emailSelectorQa.ccLabel">{{ nom.typeCC }}</span>
+        </div>
+        <div [gainsightId]="emailSelectorQa.ccInput">
+            <contact-input
+                [contacts]="contactsForPicklist()"
+                [(selected)]="ccs"
+                [placeholder]="nom.enterContactNameOrEmail"
+                [tooltip]="nom.searchForContactsTooltip"
+                (searchIconClicked)="searchForContacts($event, eMailType.CC)"
+            ></contact-input>
+        </div>
+    }
+
+    <!-- Bcc row -->
+    @if (showBCC()) {
+        <div class="email-selector-label-row email-selector-label-row-sub">
+            <span class="email-selector-label" [gainsightId]="emailSelectorQa.bccLabel">{{ nom.typeBCC }}</span>
+        </div>
+        <div [gainsightId]="emailSelectorQa.bccInput">
+            <contact-input
+                [contacts]="contactsForPicklist()"
+                [(selected)]="bccs"
+                [placeholder]="nom.enterContactNameOrEmail"
+                [tooltip]="nom.searchForContactsTooltip"
+                (searchIconClicked)="searchForContacts($event, eMailType.BCC)"
+            ></contact-input>
+        </div>
+    }
+</div>
