+import { ReportWizardDialogPanelService } from "Reporting/dialog/services/report-wizard-dialog-panel.service";
+import { qaDom, TEST_DOM_STABLE_ID_ATTRIBUTE } from "shared/testing/by-qa-id";
+import { configureStandalonePageTest } from "shared/testing/configure-standalone-page-test";
+import { detectChangesAndWhenStable } from "shared/testing/detect-changes-helpers";
+import { createMockCurrentContext } from "shared/testing/mock-current-context";
+import { ModusButtonComponent } from "shared/controls/modus-button/modus-button.component";
+
+import { EmailSelectorComponent } from "./email-selector.component";
+import { EMAIL_SELECTOR_QA } from "./email-selector-qa";
+
+// ─────────────────────────────────────────────────────────────────────────────
+// EmailSelectorComponent — `configureStandalonePageTest` (renderTemplate: false),
+// shared `context` for wemiException spies. See angular-unit-testing.md, FRONTEND_CONVENTIONS §7.
+// Locks the behavior of:
+//   - Initial recipient distribution after getContacts completes
+//   - distributeInitialRecipients routing by EMailType + show CC/BCC toggles
+//   - ngOnInit contact loading (server → pool, skip contacts without email,
+//     DisplayAddress construction)
+//   - getValidatedContactsForSubmit (error when empty, delegates to collectValidatedEmailContacts)
+//   - onContactsSelected (add, dedup, missing-email, error message format,
+//     appending to pool, routing by context type)
+//   - contactsForPicklist excludes already-used contact ids
+//   - resetRecipientFields clears all rows + hides Cc/Bcc
+// ─────────────────────────────────────────────────────────────────────────────
+
+function makeContact(over: Partial<ContactForPicklist> = {}): ContactForPicklist {
+    const c = new ContactForPicklist();
+    c.DisplayName = "Name";
+    c.Email = "name@example.com";
+    c.Title = "";
+    c.ContactID = 1;
+    c.CompanyName = "";
+    c.CompanyID = 0;
+    c.UserID = "";
+    c.UserDeleted = false;
+    c.ContactPicture = "";
+    c.EmailType = EMailTypes.To;
+    c.DisplayAddress = "";
+    c.Tel = "";
+    c.Cel = "";
+    Object.assign(c, over);
+    return c;
+}
+
+describe("EmailSelectorComponent", () => {
+    let fixture: ComponentFixture<EmailSelectorComponent>;
+    let component: EmailSelectorComponent;
+    let contactsChanged$: Subject<ContactsSelectedArgs>;
+    let getContactsSpy: Mock;
+    let showErrorSpy: Mock;
+
+    async function setupComponent(options: {
+        poolFromApi?: ContactForPicklist[] | { error: any };
+        initialContacts?: ContactForPicklist[];
+        /** When true, keeps the real template for DOM / `data-gainsight` assertions. */
+        renderTemplate?: boolean;
+        /** When true, compiles the real `ModusButtonComponent` so inner-button clicks reach `(buttonClick)`. */
+        wireModusButton?: boolean;
+    } = {}): Promise<void> {
+        TestBed.resetTestingModule();
+        contactsChanged$ = new Subject<ContactsSelectedArgs>();
+        const mockContactService = {
+            contactsHaveChangedEvent: contactsChanged$.asObservable(),
+            showForMultiSelect: vi.fn()
+        } as unknown as SelectContactPopoverService;
+
+        const apiResult = options.poolFromApi === undefined
+            ? { error: null, value: [] as ContactForPicklist[] }
+            : Array.isArray(options.poolFromApi)
+                ? { error: null, value: options.poolFromApi }
+                : options.poolFromApi;
+
+        getContactsSpy = vi.fn().mockResolvedValue(apiResult);
+
+        const ctx = createMockCurrentContext({
+            api: {
+                CompanySystem: {
+                    getContacts: getContactsSpy
+                }
+            }
+        });
+        showErrorSpy = ctx["wemiException"].ShowErrorFromServer as Mock;
+
+        const { fixture: f, component: c } = await configureStandalonePageTest(EmailSelectorComponent, {
+            context: ctx,
+            renderTemplate: options.renderTemplate ?? false,
+            extraImports: options.wireModusButton ? [ModusButtonComponent] : undefined,
+            providers: [
+                { provide: SelectContactPopoverService, useValue: mockContactService },
+                ReportWizardLogicService,
+                ReportWizardDialogPanelService,
+            ]
+        });
+        fixture = f;
+        component = c;
+
+        fixture.componentRef.setInput(
+            "nomenclatureInput",
+            mergeReportWizardNomenclature({
+                oneRecipientRequired: "One recipient required",
+                duplicateRecipients: "Duplicate:",
+                missingEMails: "Missing email for:"
+            })
+        );
+        if (options.initialContacts) {
+            fixture.componentRef.setInput("initialContactsInput", options.initialContacts);
+        }
+    }
+
+    /**
+     * One async settle + one extra OnPush flush for template queries (same shape as Reporting specs).
+     */
+    async function stableAfterTemplateRender(): Promise<void> {
+        await detectChangesAndWhenStable(fixture);
+        fixture.detectChanges();
+    }
+
+    describe("Business Logic", () => {
+
+    // ==========================================================================
+    // 1. ngOnInit + server pool loading
+    // ==========================================================================
+
+    describe("ngOnInit contact loading", () => {
+        it("calls CompanySystem.getContacts", async () => {
+            await setupComponent();
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+            expect(getContactsSpy).toHaveBeenCalled();
+        });
+
+        it("populates allContacts with only contacts that have Email", async () => {
+            await setupComponent({
+                poolFromApi: [
+                    makeContact({ ContactID: 1, Email: "a@x.com", DisplayName: "A" }),
+                    makeContact({ ContactID: 2, Email: "", DisplayName: "B" })
+                ]
+            });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+
+            const pool = component.allContacts();
+            expect(pool.map(c => c.ContactID)).toEqual([1]);
+        });
+
+        it("builds DisplayAddress as 'Name (email)'", async () => {
+            await setupComponent({
+                poolFromApi: [makeContact({ ContactID: 1, Email: "a@x.com", DisplayName: "Jane" })]
+            });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+
+            expect(component.allContacts()[0].DisplayAddress).toBe("Jane (a@x.com)");
+        });
+
+        it("overwrites server mailing DisplayAddress with Name (email) for the picklist", async () => {
+            await setupComponent({
+                poolFromApi: [
+                    makeContact({
+                        ContactID: 1,
+                        Email: "a@x.com",
+                        DisplayName: "Jane",
+                        DisplayAddress: "123 Main St\nCity, ST 00000",
+                    }),
+                ],
+            });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+
+            expect(component.allContacts()[0].DisplayAddress).toBe("Jane (a@x.com)");
+        });
+
+        it("forwards server errors to wemiException.ShowErrorFromServer", async () => {
+            await setupComponent({ poolFromApi: { error: "boom" } });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+
+            expect(showErrorSpy).toHaveBeenCalledWith("boom");
+            expect(component.allContacts()).toEqual([]);
+        });
+    });
+
+    // ==========================================================================
+    // 2. Initial recipient distribution (after getContacts)
+    // ==========================================================================
+
+    describe("initial recipient distribution", () => {
+        it("routes To recipients from initialContacts when API pool is empty", async () => {
+            await setupComponent({
+                poolFromApi: [],
+                initialContacts: [makeContact({ ContactID: 5, EmailType: EMailTypes.To })]
+            });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+
+            expect(component.tos().length).toBe(1);
+            expect(component.tos()[0].ContactID).toBe(5);
+        });
+
+        it("routes To recipients into tos when pool arrives", async () => {
+            const poolContact = makeContact({ ContactID: 5, Email: "p@x.com", DisplayName: "Pool" });
+            await setupComponent({
+                poolFromApi: [poolContact],
+                initialContacts: [makeContact({ ContactID: 5, EmailType: EMailTypes.To })]
+            });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+            fixture.detectChanges();
+
+            expect(component.tos().length).toBe(1);
+            expect(component.tos()[0].ContactID).toBe(5);
+        });
+
+        it("resolves requested contact against pool (uses pool instance)", async () => {
+            const poolContact = makeContact({
+                ContactID: 5,
+                Email: "p@x.com",
+                DisplayName: "Pool",
+                DisplayAddress: "Pool (p@x.com)"
+            });
+            const requested = makeContact({ ContactID: 5, EmailType: EMailTypes.To, DisplayName: "Stale" });
+
+            await setupComponent({ poolFromApi: [poolContact], initialContacts: [requested] });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+            fixture.detectChanges();
+
+            expect(component.tos()[0]).toBe(poolContact);
+        });
+
+        it("keeps the requested instance when pool does not contain the id (new contact)", async () => {
+            const requested = makeContact({
+                ContactID: 999, EmailType: EMailTypes.To, DisplayName: "New", Email: "n@x.com"
+            });
+            await setupComponent({
+                poolFromApi: [makeContact({ ContactID: 1, Email: "p@x.com" })],
+                initialContacts: [requested]
+            });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+            fixture.detectChanges();
+
+            expect(component.tos()[0]).toBe(requested);
+        });
+
+        it("routes CC recipients into ccs and reveals showCC", async () => {
+            await setupComponent({
+                poolFromApi: [makeContact({ ContactID: 1, Email: "a@x.com" })],
+                initialContacts: [makeContact({ ContactID: 1, EmailType: EMailTypes.CC })]
+            });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+            fixture.detectChanges();
+
+            expect(component.ccs().length).toBe(1);
+            expect(component.showCC()).toBe(true);
+        });
+
+        it("routes BCC recipients into bccs and reveals showBCC", async () => {
+            await setupComponent({
+                poolFromApi: [makeContact({ ContactID: 1, Email: "a@x.com" })],
+                initialContacts: [makeContact({ ContactID: 1, EmailType: EMailTypes.BCC })]
+            });
+            await detectChangesAndWhenStable(fixture);
+            fixture.detectChanges();
+            fixture.detectChanges();
+
+            expect(component.bccs().length).toBe(1);
+            expect(component.showBCC()).toBe(true);
+        });
+
+        it("resets recipient fields when requested list is empty but pool is non-empty", async () => {
+            await setupComponent({
+                poolFromApi: [makeContact({ ContactID: 1, Email: "a@x.com" })],
