+
+        if (contactsToAddToPool.length) {
+            this.allContacts.update((current) => [...current, ...contactsToAddToPool]);
+        }
+
+        if (toAdd.length) {
+            switch (type) {
+                case EMailTypes.To: {
+                    this.tos.update((prev) => [...prev, ...toAdd]);
+                    break;
+                }
+                case EMailTypes.CC: {
+                    this.ccs.update((prev) => [...prev, ...toAdd]);
+                    break;
+                }
+                case EMailTypes.BCC: {
+                    this.bccs.update((prev) => [...prev, ...toAdd]);
+                    break;
+                }
+            }
+        }
+
+        let errorMessage = "";
+        if (missingEmail) {
+            errorMessage = `${this.nomenclature().missingEMails} ${missingEmail}`;
+        }
+        if (duplicates) {
+            if (errorMessage) {
+                errorMessage += "; ";
+            }
+            errorMessage += `${this.nomenclature().duplicateRecipients} ${duplicates}`;
+        }
+        if (errorMessage) {
+            this.wemiException.ShowErrorFromServer(errorMessage);
+        }
+    }
+
+    private allSelectedContacts(): ContactForPicklist[] {
+        return [...this.tos(), ...this.ccs(), ...this.bccs()];
+    }
+
+    /** Email picklist label: always Name (email), not mailing DisplayAddress from the API. */
+    private formatDisplayAddress(contact: ContactForPicklist): void {
+        contact.DisplayAddress = `${contact.DisplayName} (${contact.Email})`;
+    }
+}
