+        const format$ = toObservable(this.format, opts);
+        const isEmailMode$ = toObservable(this.isEmailMode, opts);
+        const selectedReportIsPdfOnly$ = toObservable(this.selectedReportIsPdfOnly, opts);
+        const selectedProjectIds$ = toObservable(this.selectedProjectIds, opts);
