+            this.title.set(nom.dialogTitleForTransmittals || nom.eMailTitle);
+        } else {
+            this.title.set(this.isEmailMode() ? nom.eMailTitle : nom.dialogTitle);
+        }
+    }
+
+    private setDataViewsFromOptions(args: ReportWizardLoadArgs): void {
+        const options = args?.options;
+        const selectedViewId = options?.ViewId ?? 0;
+        const currentViewId = options?.CurrentViewId ?? 0;
+        this.dataViewId.set(selectedViewId || currentViewId || 0);
+        this._dataViewRawItems.set([]);
+    }
+
+    private applyViewsFromApi(views: ListView[] | null | undefined): void {
+        if (!views?.length) {
+            this._dataViewRawItems.set([]);
+            return;
+        }
+        // GetComponentSettings uses default JSON casing (PascalCase), not camelCase — same as reports on this config.
+        const items: DropdownItem[] = views.map((view) => {
+            const row = view as ListView & { RecordId?: number; ViewName?: string };
+            return {
+                LookupListID: row.RecordId ?? 0,
+                Description: row.ViewName ?? "",
+                checked: false,
+            };
+        });
+        this._dataViewRawItems.set(items);
+    }
+
+    protected setEmailMode(isEmail: boolean): void {
+        if (!isEmail && this._modalHost.isMaximized()) {
+            this._modalHost.toggleMaximized();
+        }
+        this.isEmailMode.set(isEmail);
+        if (this.isBehaviorMode()) {
+            this.resolveBehaviorTitle(this.nomenclature());
+        } else {
+            const nom = this.nomenclature();
+            this.title.set(isEmail ? nom.eMailTitle : nom.dialogTitle);
+        }
+        this._reportWizardGridService.hideIncludeAsColumn(!isEmail);
+
+        if (isEmail) {
+            this.applySmallAttachmentDefaultsForEmail();
+        }
+    }
+
+    protected onBodyEditorCreated(editor: any): void {
+        const toolbar = editor?.getModule?.("toolbar")?.container as HTMLElement | undefined;
+        toolbar?.addEventListener("mousedown", this._preventQuillButtonMouseDown, true);
+    }
+
+    /** Matches ReportingWizard.js adjustUIForEMailChange: single-record email + total attachment size under 5 MB defaults IncludeAs to Attachment. */
+    private applySmallAttachmentDefaultsForEmail(): void {
+        if (!this.isEmailMode() || this.recordOption() !== RECORD_OPTIONS.Single) {
+            return;
+        }
+        const attachments = this._reportWizardGridService.getAttachments();
+        const totalSizeMb = attachments.reduce((sum, a) => sum + (a.FileSize ?? 0), 0) / 1048576;
+        if (totalSizeMb < 5) {
+            this._reportWizardGridService.updateAllAttachmentsIncludeAs(IncludeAsTypes.Attachment);
+        }
+    }
+
+    /**
+     * Applies {@link ReportWizardConfig.reports} to `this.reports`. For Budget, filters by
+     * `actualTableType` vs each report's {@link ReportLite.ActualTableType}.
+     */
+    private loadReportTemplates(reports: ReportLite[] | null | undefined): void {
+        const list = reports ?? [];
+        if (this.tableType() !== PrologTableTypes.Budget) {
+            this.reports.set(list);
+            return;
+        }
+
+        const actualTableType = this.actualTableType();
+        this.reports.set(
+            list.filter((report) =>
+                budgetReportMatchesWizardContext(
+                    actualTableType,
+                    report.ActualTableType ?? PrologTableTypes.None
+                )
+            )
+        );
+    }
+
+    protected onReportSelectionChanged(items: IDropdownMultiSelectItem[]): void {
+        const selected = items?.[0] as DropdownItem;
+        this.reportId.set(selected?.LookupListID ?? 0);
+    }
+
+    protected onFormatSelectionChanged(items: IDropdownMultiSelectItem[]): void {
+        const selected = items?.[0] as DropdownItem;
+        this.format.set(selected?.LookupListID ?? FormatTypes.Pdf);
+        this.tryBuildFooterMenuItems();
+    }
+
+    protected onDataViewSelectionChanged(items: IDropdownMultiSelectItem[]): void {
+        const selected = items?.[0] as DropdownItem;
+        this.dataViewId.set(selected?.LookupListID ?? 0);
+    }
+
+    protected openFooterMenu(): void {
+        const items = this.footerMenuItems();
+        if (items.length > 0 && this.footerMenu && this.footerMenuTrigger) {
+            this.footerMenu.show(this.footerMenuTrigger.element.nativeElement);
+        }
+    }
+
+    protected onFooterMenuSelect(args: MenuItemSelectedArgs): void {
+        const value = args.Item?.value;
+        if (value === ReportWizardDialogComponent.FOOTER_MENU_EMAIL) {
+            this.setEmailMode(true);
+            return;
+        }
+        const action = Number(value) as ReportActionValue;
+        if (action === REPORT_ACTION.Download || action === REPORT_ACTION.FileLibrary) {
+            this.onReportAction(action);
+        }
+    }
+
+    protected onReportAction(action: ReportActionValue): void {
+        if (this.isAdHocTab() && this.format() === FormatTypes.Excel) {
+            const handler = this._loadArgs?.options?.AdHocToExcelHandler;
+            if (handler) {
+                handler.viewInExcel(this.fileName());
+                this._dialogService.close(true);
+                return;
+            }
+        }
+
+        if (this.isEmailMode()) {
+            void this._panelService.requestValidatedEmailContacts().then((contacts) => {
+                if (!contacts) {
+                    return;
+                }
+                this.reportRequestRefValue.Contacts = contacts;
+                this.initiateReportAction(action);
+            });
+            return;
+        }
+        this.initiateReportAction(action);
+    }
+
+    private initiateReportAction(action: ReportActionValue): void {
+        const validateContacts = () => (this.reportRequestRefValue?.Contacts?.length ?? 0) > 0;
+        const nom = this.nomenclature();
+        const state = {
+            reportId: this.reportId(),
+            format: this.format(),
+            fileName: this.fileName(),
+            recordOption: this.recordOption(),
+            selectedProjectIds: this.selectedProjectIds() ?? [],
+            attachments: this._reportWizardGridService.getAttachments(),
+            subject: this.subject(),
+            body: this.body(),
+            contacts: this.reportRequestRefValue?.Contacts ?? [],
+            tableType: this.tableType(),
+            keyValues: this.keyValues(),
+            behavior: this.behavior(),
+            isAdHocReport: this.isAdHocTab(),
+            adHocViewId: this.dataViewId(),
+            isForMultipleRecords: this.isForMultipleRecords(),
+            includeFileNamesInHeaders: this.includeFileNamesInHeaders(),
+            additionalDataFilters: this._loadArgs?.options?.AdditionalDataFilters,
+            options: {
+                printingVisibleItems: this._loadArgs?.options?.PrintingVisibleItems ?? false,
+                filters: this._loadArgs?.options?.Filters ?? [],
+                actualTableType: this._loadArgs?.actualTableType,
+                currentViewId: this._loadArgs?.options?.CurrentViewId,
+                defaultGroup: this._loadArgs?.options?.DefaultGroup,
+                defaultSort: this._loadArgs?.options?.DefaultSort,
+                columns: this._loadArgs?.options?.Columns ?? [],
+                fromAngular: this._loadArgs?.options?.FromAngular ?? false,
+            },
+        };
+
+        const err = this._logicService.validateBeforeInitiate(state, action, nom, validateContacts);
+        if (err) {
+            this.wemiException.ShowErrorFromServer(err);
+            return;
+        }
+
+        const request = this._logicService.buildReportRequest(state, action);
+        this.loading.set(true);
+        this._logicService.initiateReport(request, action, nom, () => this._dialogService.close(true), state)
+            .finally(() => this.loading.set(false));
+    }
+
+    protected trimSubjectOnBlur(): void {
+        const trimmed = this.subject().trim();
+        if (trimmed !== this.subject()) {
+            this.subject.set(trimmed);
+        }
+    }
+
+    protected trimFileNameOnBlur(): void {
+        const trimmed = this.fileName().trim();
+        if (trimmed !== this.fileName()) {
+            this.fileName.set(trimmed);
+        }
+    }
+
+    protected onCancel(): void {
+        this.closeWindow();
+    }
+
+    protected override closeWindow(): void {
+        this.dismissFooterMenu();
+        this.dismissContactPopover();
+        this._selectContactPopoverService.notifyPopoverClosed();
+        this._dialogService.close();
+    }
+
+    /** Closes the footer more-menu via the host ViewChild (same pattern as links-panel / chatbot). */
+    private dismissFooterMenu(): void {
+        this.footerMenu?.closePopover();
+    }
+
+    private isContactPopoverOpen(): boolean {
+        if (this._internalContactPopover?.showPopover()) {
+            return true;
+        }
+        return !this.shouldRenderInternalPopover && this._lastContactPopoverShowArgs !== null;
+    }
+
+    /** Closes shell (ViewChild) or DEF host (`select-contact-popover` custom element) contact popover. */
+    private dismissContactPopover(): void {
+        if (this._internalContactPopover?.showPopover()) {
+            this._internalContactPopover.closePopover();
+            return;
+        }
+        const hostInstance = this.getHostContactPopoverInstance();
+        if (hostInstance?.showPopover()) {
+            hostInstance.closePopover();
+        }
+    }
+
+    /** DEF iframe host popover registered as a custom element in fdef.bootstrap.ts. */
+    private getHostContactPopoverInstance(): SelectContactPopoverComponent | null {
+        const el = document.querySelector(SelectContactPopoverComponent.SELECTOR) as HTMLElement | null;
+        if (!el) {
+            return null;
+        }
+        const strategy = (el as SelectContactPopoverNgElement).ngElementStrategy;
+        return strategy?.componentRef?.instance ?? null;
+    }
+}
+
+/** Angular custom-element bridge for the page-level select-contact-popover (DEF host). */
+interface SelectContactPopoverNgElement extends HTMLElement {
+    ngElementStrategy?: {
+        componentRef?: {
+            instance?: SelectContactPopoverComponent;
+        };
+    };
+}
