+/**
+ * Stable `data-gainsight` ids for {@link ReportWizardGridComponent} (template + unit tests).
+ */
+export const REPORT_WIZARD_GRID_QA = {
+    /** Outer container around `igx-grid` + drag/drop. */
+    root: "report-wizard-grid-root",
+    /** Infragistics grid host. */
+    grid: "report-wizard-grid-igx-grid",
+    /** Drag-handle icon template host (row reorder). */
