+/**
+ * Stable `data-gainsight` id strings for ReportWizardProject (Gainsight + unit tests).
+ * Re-export the same object from the component; do not duplicate literals in specs.
+ */
+export const REPORT_WIZARD_PROJECT_QA = {
+    /** Outermost panel when `showComponent` is true. */
+    projectsContainer: "report-wizard-project-container",
+    /** Column header text (e.g. “Project”). */
+    projectColumnCaption: "report-wizard-project-column-caption",
+    /** #projectFilterRoot — host for filter control + filter popup. */
+    projectFilterHost: "report-wizard-project-filter-host",
+    projectFilterTrigger: "report-wizard-project-filter",
+    selectAllCheckbox: "report-wizard-project-select-all",
+    currentProjectRow: "report-wizard-project-current-row",
+    /** Label text for the fixed “current context” project row. */
+    currentProjectNameLabel: "report-wizard-project-current-name",
+    /** Prefix; each other row uses `otherProjectRowGainsightId(projectId)` in the template. */
+    otherProjectRowPrefix: "report-wizard-project-other-row",
+    /** List body for “other” projects; toggles the `collapsed` class. */
+    otherProjectsList: "report-wizard-project-other-list",
+    expandToggle: "report-wizard-project-expand",
+
+    /** Workflow filter popup panel (visible when filter is open). */
+    filterPopup: "report-wizard-project-filter-popup",
+    /** Clear filters button inside the popup. */
+    clearFiltersButton: "report-wizard-project-clear-filters",
+    /** Disabled checkbox on the fixed current-project row. */
+    currentProjectCheckbox: "report-wizard-project-current-checkbox",
+
+    /** Prefix for filter checkbox inputs — use {@link filterCheckboxGainsightId}. */
+    filterCheckboxPrefix: "report-wizard-project-filter-checkbox",
+    /** Prefix for “other project” row checkbox — use {@link otherProjectCheckboxGainsightId}. */
+    otherProjectCheckboxPrefix: "report-wizard-project-other-checkbox",
+} as const;
+
+/** Stable `data-gainsight` for a non–current project row (includes project id in the id). */
+export function otherProjectRowGainsightId(projectId: number): string {
+    return `${REPORT_WIZARD_PROJECT_QA.otherProjectRowPrefix}-${projectId}`;
+}
+
+/** Stable id for a workflow filter checkbox (escaped workflow label). */
+export function filterCheckboxGainsightId(workflowLabel: string): string {
+    const safe = encodeURIComponent(workflowLabel).replace(/%/g, "_");
+    return `${REPORT_WIZARD_PROJECT_QA.filterCheckboxPrefix}-${safe}`;
+}
+
+/** Stable id for the per-row checkbox in the “other projects” list. */
+export function otherProjectCheckboxGainsightId(projectId: number): string {
+    return `${REPORT_WIZARD_PROJECT_QA.otherProjectCheckboxPrefix}-${projectId}`;
+}
