+/* Matches ReportingWizard.css project list styling - uses CSS variables from Default.css */
+:host {
+    display: flex;
+    flex-direction: column;
+    flex: 1 1 auto;
+    min-height: 0;
+    overflow: hidden;
+}
+
+/* Filter menu extends past the header; overflow:hidden on :host clips the bottom (e.g. Clear). */
+:host.filter-popup-open {
+    overflow: visible;
+    position: relative;
+    z-index: 10;
+}
+
+/* No DOM when showComponent is false — do not reserve flex space */
+:host:empty {
+    display: none;
+}
+
+.ProjectsContainer {
+    display: flex;
+    flex-direction: column;
+    flex: 1 1 auto;
+    min-height: 0;
+    overflow: hidden;
+    padding-top: 15px;
+}
+
+:host.filter-popup-open .ProjectsContainer {
+    overflow: visible;
+}
+
+/* position + z-index so the filter dropdown (overflows below this row) paints above .AllProjectsList */
+.ProjectHeaderRow {
+    position: relative;
+    z-index: 2;
+    display: flex;
+    flex-direction: row;
+    flex-wrap: nowrap;
+    align-items: center;
+    flex-shrink: 0;
+    width: calc(100% - 2px);
+    min-width: 0;
+    height: 40px;
+    line-height: 40px;
+    background-color: transparent;
+    border: 1px solid var(--neutral-gray-1);
+    box-sizing: border-box;
+}
+
+.ProjectColumnCaption {
+    font-weight: 700;
+}
+
+/* Same flex centering pattern as .ProjectFilter + .project-filter-trigger so icon-only modus-buttons align vertically. */
+.ProjectHeaderRow .ProjectExpandCollapse {
+    flex: 0 0 20px;
+    margin-left: 10px;
+    width: 20px;
+    min-height: 40px;
+    align-self: stretch;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    line-height: normal;
+    overflow: visible;
+}
+
+.ProjectRow .ProjectExpandCollapse {
+    flex: 0 0 20px;
+    margin-left: 10px;
+    width: 20px;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    line-height: normal;
+}
+
+.project-expand-trigger {
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    width: 100%;
+    height: 100%;
+}
+
+.ProjectHeaderRow .ProjectSelect {
+    flex: 0 0 28px;
+    width: 28px;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+}
+
+.ProjectRow .ProjectSelect {
+    flex: 0 0 20px;
+    width: 20px;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+}
+
+.ProjectSelect > input {
+    margin: 0;
+    cursor: pointer;
+}
+
+.ProjectRow > .ProjectName {
+    color: var(--blue-blue);
+    margin-left: 10px;
+    margin-right: 8px;
+    flex: 1 1 auto;
+    min-width: 0;
+}
+
+.ProjectHeaderRow > .ProjectName {
+    flex: 1 1 auto;
+    min-width: 0;
+    margin-left: 10px;
+    margin-right: 8px;
+}
+
+.ProjectFilter {
+    flex: 0 0 40px;
+    flex-shrink: 0;
+    width: 40px;
+    min-width: 40px;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    height: 40px;
+    overflow: visible;
+    position: relative;
+}
+
+.project-filter-trigger {
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    width: 100%;
+    height: 100%;
+}
+
+.ProjectFilterList {
+    position: absolute;
+    right: 0;
+    top: 100%;
+    z-index: 10050;
+    width: 162px;
+    max-height: 201px;
+    background: var(--neutral-gray-light);
+    box-shadow:
+        0 0 0 1px color-mix(in srgb, var(--neutral-gray-9) 5%, transparent),
+        0 1px 3px color-mix(in srgb, var(--neutral-gray-9) 15%, transparent);
+    overflow-y: auto;
+}
+
+.ProjectFilterList ul {
+    list-style: none;
+    margin: 0;
+    padding: 0;
+}
+
+.ProjectFilterList li {
+    height: 40px;
+    color: var(--neutral-gray-8);
+    font-weight: 400;
+    display: flex;
+    align-items: center;
+    cursor: pointer;
+}
+
+.ProjectFilterList li.clear-item {
+    border-top: 1px solid var(--neutral-gray-0);
+    text-align: center;
+    justify-content: center;
+    padding-left: 0.25rem;
+    padding-right: 0.25rem;
+    box-sizing: border-box;
+}
+
+.ProjectFilterList li span {
+    text-overflow: ellipsis;
+    white-space: nowrap;
+    overflow-x: clip;
+}
+
+.ProjectFilterList li:hover {
+    background-color: var(--neutral-gray-0);
+}
+
+.ProjectFilterList input {
+    margin: 0 8px 0 14px;
+    cursor: pointer;
+}
+
+.ProjectRow {
+    display: flex;
+    align-items: center;
+    width: calc(100% - 2px);
+    height: 34px;
+    line-height: 34px;
+    border: 1px solid var(--neutral-gray-1);
+    border-top-width: 0;
+    background-color: var(--neutral-gray-light);
+}
+
+.ProjectRow:hover {
+    background: var(--neutral-gray-0);
+}
+
+.ProjectRow.Selected {
+    background: var(--modeColor-semantic-primary-pale);
+}
+
+.ProjectRow.current-project .ProjectName {
+    color: inherit;
+}
+
+/* Fills space below the header row; min-height:0 so flex can shrink and overflow-y can scroll fully */
+.AllProjectsList {
+    position: relative;
+    z-index: 0;
+    flex: 1 1 0%;
+    min-height: 0;
+    width: 100%;
+    box-sizing: border-box;
+    overflow-y: auto;
+    overflow-x: hidden;
+    padding-bottom: 4px;
+}
+
+.OtherProjectsList {
+    min-height: 0;
+}
+
+.OtherProjectsList.collapsed {
+    display: none;
+}
+
+.EllipsisOverflow {
+    text-overflow: ellipsis;
+    white-space: nowrap;
+    overflow: hidden;
+}
