@@ -0,0 +1,117 @@
+@if (showComponent()) {
+@let nom = nomenclature();
+<div class="ProjectsContainer" [gainsightId]="reportWizardProjectQa.projectsContainer">
+    <div class="ProjectHeaderRow">
+        <div class="ProjectExpandCollapse">
+            <modus-button
+                class="project-expand-trigger"
+                [gainsightId]="reportWizardProjectQa.expandToggle"
+                [type]="'button'"
+                [variant]="'borderless'"
+                [color]="'tertiary'"
+                [size]="'sm'"
+                [label]="''"
+                [modusIconLeft]="expanded() ? 'expand_more' : 'chevron_right'"
+                (buttonClick)="toggleExpand()"
+                (click)="$event.stopPropagation()">
+            </modus-button>
+        </div>
+        <div class="ProjectSelect Header">
+            @if (visibleProjects().length > 0) {
+                <input type="checkbox"
+                       [gainsightId]="reportWizardProjectQa.selectAllCheckbox"
+                       [checked]="isSelectAllChecked()"
+                       (change)="onSelectAllChange($any($event.target).checked)" />
+            }
+        </div>
+        <div class="ProjectName">
+            <span class="ProjectColumnCaption"
+                  [gainsightId]="reportWizardProjectQa.projectColumnCaption">{{ projectColumnCaptionText() }}</span>
+        </div>
+        <div class="ProjectFilter"
+             #projectFilterRoot
+             [gainsightId]="reportWizardProjectQa.projectFilterHost">
+
+            <modus-button
+                class="project-filter-trigger"
+                [gainsightId]="reportWizardProjectQa.projectFilterTrigger"
+                [type]="'button'"
+                [variant]="'borderless'"
+                [color]="'tertiary'"
+                [size]="'sm'"
+                [label]="''"
+                [modusIconLeft]="'filter'"
+                [modusTooltip]="nom.filterTooltip"
+                [tooltipPosition]="'left'"
+                (buttonClick)="toggleFilterPopup()"
+                (click)="$event.stopPropagation()">
+            </modus-button>
+            @if (filterPopupVisible()) {
+                <div class="ProjectFilterList ThinScrollbar" [gainsightId]="reportWizardProjectQa.filterPopup">
+                    <ul>
+                        @for (filter of filterOptions(); track filter) {
+                            <li (click)="$event.stopPropagation()">
+                                <input type="checkbox"
+                                       [gainsightId]="filterCheckboxGainsightId(filter)"
+                                       [checked]="activeFilters().has(filter)"
+                                       (change)="onFilterCheckboxChange(filter, $any($event.target).checked)" />
+                                <span [title]="filter">{{ filter }}</span>
+                            </li>
+                        }
+                        <li class="clear-item">
+                            <modus-button
+                                [gainsightId]="reportWizardProjectQa.clearFiltersButton"
+                                [type]="'button'"
+                                [variant]="'borderless'"
+                                [color]="'tertiary'"
+                                [size]="'sm'"
+                                [fullWidth]="true"
+                                [label]="nom.clearButton"
+                                (buttonClick)="onClearFilters()"
+                                (click)="$event.stopPropagation()">
+                            </modus-button>
+                        </li>
+                    </ul>
+                </div>
+            }
+        </div>
+    </div>
+
+    <div class="AllProjectsList">
+        @if (showCurrentProjectRow()) {
+            <div class="ProjectRow current-project" [gainsightId]="reportWizardProjectQa.currentProjectRow">
+                <div class="ProjectExpandCollapse"><span>&nbsp;</span></div>
+                <div class="ProjectSelect">
+                    <input type="checkbox" checked disabled [gainsightId]="reportWizardProjectQa.currentProjectCheckbox" />
+                </div>
+                <div class="ProjectName EllipsisOverflow">
+                    <span [gainsightId]="reportWizardProjectQa.currentProjectNameLabel"
+                          [title]="currentProjectRowLabel()">{{ currentProjectRowLabel() }}</span>
+                </div>
+            </div>
+        }
+
+        <div class="OtherProjectsList"
+             [gainsightId]="reportWizardProjectQa.otherProjectsList"
+             [class.collapsed]="!expanded()">
+            @for (row of visibleProjects(); track row.ProjectID) {
+                <div class="ProjectRow"
+                     [gainsightId]="reportWizardProjectQa.otherProjectRowPrefix + '-' + row.ProjectID"
+                     [class.Selected]="row.IsSelected"
+                     [attr.data-workflow-state-name]="row.WorkflowStateLabel">
+                    <div class="ProjectExpandCollapse"><span>&nbsp;</span></div>
+                    <div class="ProjectSelect">
+                        <input type="checkbox"
+                               [gainsightId]="otherProjectCheckboxGainsightId(row.ProjectID)"
+                               [checked]="row.IsSelected"
+                               (change)="onProjectSelectionChange(row, $any($event.target).checked)" />
+                    </div>
+                    <div class="ProjectName EllipsisOverflow">
+                        <span [title]="row.DisplayProjectName">{{ row.DisplayProjectName }}</span>
+                    </div>
+                </div>
+            }
+        </div>
+    </div>
+</div>
+}
