@@ -0,0 +1,846 @@
+/* eslint-disable @typescript-eslint/no-explicit-any */
+import { vi } from "vitest";
+import { ComponentFixture } from "@angular/core/testing";
+import { By } from "@angular/platform-browser";
+
+import { qaDom, TEST_DOM_STABLE_ID_ATTRIBUTE, type DomQuerier } from "shared/testing/by-qa-id";
+import { ProjectLite } from "Reporting/dialog/models/ProjectLite";
+import { configureStandalonePageTest } from "shared/testing/configure-standalone-page-test";
+import { detectChangesAndWhenStable } from "shared/testing/detect-changes-helpers";
+import { createMockCurrentContext } from "shared/testing/mock-current-context";
+import { PrologTableTypes } from "shared/enums/PrologTableTypes";
+
+import { ReportWizardDialogPanelService } from "Reporting/dialog/services/report-wizard-dialog-panel.service";
+import { ReportWizardProjectComponent, ProjectRow } from "./report-wizard-project.component";
+import { ModusButtonComponent } from "shared/controls/modus-button/modus-button.component";
+import {
+    filterCheckboxGainsightId,
+    otherProjectCheckboxGainsightId,
+    otherProjectRowGainsightId,
+    REPORT_WIZARD_PROJECT_QA,
+} from "./report-wizard-project-qa";
+
+/**
+ * Unit tests for ReportWizardProjectComponent: project list, workflow filter, and selection
+ * for the report wizard. Business rules are covered without the real template; the UI suite
+ * uses the production template with heavy child components stubbed by NO_ERRORS_SCHEMA.
+ * UI render tests use `qaDom(fixture).query(id)` for `data-gainsight` (see `REPORT_WIZARD_PROJECT_QA`).
+ */
+describe("ReportWizardProjectComponent", () => {
+    let fixture: ComponentFixture<ReportWizardProjectComponent>;
+    let component: ReportWizardProjectComponent;
+    let mockContext: ReturnType<typeof createMockCurrentContext>;
+
+    function makeProject(over: Partial<ProjectLite> = {}): ProjectLite {
+        return {
+            ProjectID: 1,
+            ProjectName: "Project One",
+            WorkflowStateName: "Active",
+            ...over
+        };
+    }
+
+    async function setup(
+        options: {
+            projectsFromApi?: ProjectLite[];
+            tableType?: number;
+            currentProjectId?: number;
+            currentProjectName?: string;
+            showComponent?: boolean;
+            projectColumnCaption?: unknown;
+            selectAllLabel?: unknown;
+            renderTemplate?: boolean;
+        } = {}
+    ): Promise<void> {
+        mockContext = createMockCurrentContext({});
+
+        const renderTemplate = options.renderTemplate ?? false;
+        const { fixture: f, component: c } = await configureStandalonePageTest(ReportWizardProjectComponent, {
+            renderTemplate,
+            context: mockContext,
+            providers: [ReportWizardDialogPanelService],
+        });
+        fixture = f;
+        component = c;
+
+        fixture.componentRef.setInput("tableType", options.tableType ?? PrologTableTypes.RFI);
+        fixture.componentRef.setInput("currentProjectId", options.currentProjectId ?? 0);
+        fixture.componentRef.setInput("currentProjectName", (options.currentProjectName ?? "") as string);
+        fixture.componentRef.setInput("showComponent", options.showComponent ?? true);
+        fixture.componentRef.setInput("accessibleProjects", options.projectsFromApi ?? []);
+        if (options.projectColumnCaption !== undefined) {
+            fixture.componentRef.setInput("projectColumnCaption" as "projectColumnCaption", options.projectColumnCaption as string);
+        }
+        if (options.selectAllLabel !== undefined) {
+            fixture.componentRef.setInput("selectAllLabel" as "selectAllLabel", options.selectAllLabel as string);
+        }
+    }
+
+    /**
+     * Kicks the first change-detection run (starts `loadProjects`) and waits for the zone, then
+     * runs a second `detectChanges` so OnPush + signals re-render the template with loaded rows.
+     * (Two `detectChangesAndWhenStable` calls in a row were equivalent but redundant; this is the
+     * minimal “async load + one extra flush” shape.)
+     */
+    async function stableAfterLoad(): Promise<void> {
+        await detectChangesAndWhenStable(fixture);
+        fixture.detectChanges();
+    }
+
+    describe("Business Logic", () => {
+        describe("applyProjectsFromConfig when tableType and showComponent are truthy", () => {
+            it("applies accessibleProjects after the first change detection", async () => {
+                await setup({ tableType: PrologTableTypes.RFI, showComponent: true, projectsFromApi: [makeProject()] });
+                await detectChangesAndWhenStable(fixture);
+                expect((component as any).projects().length).toBe(1);
+            });
+
+            it("does not apply when showComponent is false", async () => {
+                await setup({ tableType: PrologTableTypes.RFI, showComponent: false, projectsFromApi: [makeProject()] });
+                await detectChangesAndWhenStable(fixture);
+                expect((component as any).projects().length).toBe(0);
+            });
+
+            it("does not apply when tableType is 0 (falsy)", async () => {
+                await setup({ tableType: PrologTableTypes.None, showComponent: true, projectsFromApi: [makeProject()] });
+                await detectChangesAndWhenStable(fixture);
+                expect((component as any).projects().length).toBe(0);
+            });
+
+            it("applies when tableType later becomes non-zero", async () => {
+                await setup({ tableType: PrologTableTypes.None, showComponent: true, projectsFromApi: [makeProject()] });
+                await detectChangesAndWhenStable(fixture);
+                expect((component as any).projects().length).toBe(0);
+
+                fixture.componentRef.setInput("tableType", PrologTableTypes.Project);
+                await detectChangesAndWhenStable(fixture);
+                expect((component as any).projects().length).toBe(1);
+            });
+
+            it("applies when showComponent toggles from false to true", async () => {
+                await setup({ tableType: PrologTableTypes.RFI, showComponent: false, projectsFromApi: [makeProject()] });
+                await detectChangesAndWhenStable(fixture);
+                expect((component as any).projects().length).toBe(0);
+
+                fixture.componentRef.setInput("showComponent", true);
+                await detectChangesAndWhenStable(fixture);
+                expect((component as any).projects().length).toBe(1);
+            });
+        });
+
+        describe("applyProjectsFromConfig: mapping", () => {
+            it("excludes the current project from the other-projects list", async () => {
+                await setup({
+                    tableType: PrologTableTypes.RFI,
+                    currentProjectId: 10,
+                    projectsFromApi: [
+                        makeProject({ ProjectID: 10, ProjectName: "Current" }),
+                        makeProject({ ProjectID: 11, ProjectName: "Other" }),
+                    ],
+                });
+                await stableAfterLoad();
+
+                const rows = (component as any).projects() as ProjectRow[];
+                expect(rows.length).toBe(1);
+                expect(rows[0].ProjectID).toBe(11);
+            });
+
+            it("sets IsSelected to false when the API does not send it", async () => {
+                await setup({ tableType: PrologTableTypes.RFI, projectsFromApi: [makeProject({ ProjectID: 1 })] });
+                await stableAfterLoad();
+
+                const rows = (component as any).projects() as ProjectRow[];
+                expect(rows[0].IsSelected).toBe(false);
+            });
+
+            it("maps project and workflow display fields to strings", async () => {
+                await setup({
+                    tableType: PrologTableTypes.RFI,
+                    projectsFromApi: [makeProject({ ProjectID: 1, ProjectName: "Alpha", WorkflowStateName: "Active" })],
+                });
+                await stableAfterLoad();
+
+                const row = (component as any).projects()[0] as ProjectRow;
+                expect(row.DisplayProjectName).toBe("Alpha");
+                expect(row.WorkflowStateLabel).toBe("Active");
+            });
+
+            it("builds sorted unique filter options from workflow state names", async () => {
+                await setup({
+                    tableType: PrologTableTypes.RFI,
+                    projectsFromApi: [
+                        makeProject({ ProjectID: 1, WorkflowStateName: "Closed" }),
+                        makeProject({ ProjectID: 2, WorkflowStateName: "Active" }),
+                        makeProject({ ProjectID: 3, WorkflowStateName: "Active" }),
+                    ],
+                });
+                await stableAfterLoad();
+
+                expect((component as any).filterOptions()).toEqual(["Active", "Closed"]);
+            });
+
+            it("starts with every workflow filter option checked", async () => {
+                await setup({
+                    tableType: PrologTableTypes.RFI,
+                    projectsFromApi: [
+                        makeProject({ ProjectID: 1, WorkflowStateName: "Active" }),
+                        makeProject({ ProjectID: 2, WorkflowStateName: "Closed" }),
+                    ],
+                });
+                await stableAfterLoad();
+
+                const set = (component as any).activeFilters() as Set<string>;
+                expect(set.has("Active")).toBe(true);
+                expect(set.has("Closed")).toBe(true);
+            });
+
+            it("emits empty selectedProjectIds when no row is pre-selected", async () => {
+                await setup({ tableType: PrologTableTypes.RFI, projectsFromApi: [makeProject({ ProjectID: 1 })] });
+                await stableAfterLoad();
+
+                expect(component.selectedProjectIds()).toEqual([]);
+            });
+
+            it("re-applies when accessibleProjects input changes", async () => {
+                await setup({ tableType: PrologTableTypes.RFI, projectsFromApi: [makeProject({ ProjectID: 1 })] });
+                await stableAfterLoad();
+                expect((component as any).projects().length).toBe(1);
+
+                fixture.componentRef.setInput("accessibleProjects", [
+                    makeProject({ ProjectID: 1 }),
+                    makeProject({ ProjectID: 2 }),
+                ]);
+                await detectChangesAndWhenStable(fixture);
+                expect((component as any).projects().map((r: ProjectRow) => r.ProjectID)).toEqual([1, 2]);
+            });
+        });
+
+        describe("visibleProjects (computed)", () => {
+            beforeEach(async () => {
+                await setup({
+                    tableType: PrologTableTypes.RFI,
+                    projectsFromApi: [
+                        makeProject({ ProjectID: 1, WorkflowStateName: "Active" }),
+                        makeProject({ ProjectID: 2, WorkflowStateName: "Closed" }),
+                    ],
+                });
+                await detectChangesAndWhenStable(fixture);
+            });
+
+            it("returns an empty list when the active filter set is empty", () => {
+                (component as any).activeFilters.set(new Set());
+                expect((component as any).visibleProjects()).toEqual([]);
+            });
+
+            it("keeps only projects that match a checked filter", () => {
+                (component as any).activeFilters.set(new Set(["Active"]));
+                const visible = (component as any).visibleProjects() as ProjectRow[];
+                expect(visible.map((p: ProjectRow) => p.ProjectID)).toEqual([1]);
+            });
+
+            it("returns every project when all filters stay checked", () => {
+                (component as any).activeFilters.set(new Set(["Active", "Closed"]));
+                expect(((component as any).visibleProjects() as ProjectRow[]).length).toBe(2);
+            });
+        });
+
+        describe("isSelectAllChecked (computed)", () => {
+            it("is false when there are no visible projects", async () => {
+                await setup({ tableType: PrologTableTypes.RFI, projectsFromApi: [] });
+                await detectChangesAndWhenStable(fixture);
+                expect((component as any).isSelectAllChecked()).toBe(false);
+            });
+
+            it("is true when every visible row is selected", async () => {
+                await setup({
+                    tableType: PrologTableTypes.RFI,
+                    projectsFromApi: [makeProject({ ProjectID: 1, WorkflowStateName: "Active" })],
+                });
+                await detectChangesAndWhenStable(fixture);
+                (component as any).projects.update((rows: ProjectRow[]) => rows.map((r) => ({ ...r, IsSelected: true })));
+                expect((component as any).isSelectAllChecked()).toBe(true);
+            });
+
+            it("is false when a visible row is not selected", async () => {
+                await setup({
+                    tableType: PrologTableTypes.RFI,
+                    projectsFromApi: [
+                        makeProject({ ProjectID: 1, WorkflowStateName: "Active" }),
+                        makeProject({ ProjectID: 2, WorkflowStateName: "Active" }),
+                    ],
