diff --git a/Core/Web Layer/WebUI/ps-ng/src/app/Reporting/dialog/components/report-wizard-project/report-wizard-project.component.ts b/Core/Web Layer/WebUI/ps-ng/src/app/Reporting/dialog/components/report-wizard-project/report-wizard-project.component.ts
