@@ -0,0 +1,293 @@
+import {
+    ChangeDetectionStrategy,
+    Component,
+    ElementRef,
+    HostBinding,
+    HostListener,
+    Injector,
+    OnInit,
+    ViewChild,
+    computed,
+    inject,
+    input,
+    model,
+    signal,
+} from "@angular/core";
+import { toObservable } from "@angular/core/rxjs-interop";
+import { combineLatest } from "rxjs";
+import { filter } from "rxjs/operators";
+import { CommonModule } from "@angular/common";
+import { FormsModule } from "@angular/forms";
+import { BaseComponent } from "shared/components/BaseComponent";
+import { ProjectLite } from "Reporting/dialog/models/ProjectLite";
+import { ModusButtonComponent } from "shared/controls/modus-button/modus-button.component";
+import { GainsightIdDirective } from "shared/directives/gainsightId.directive";
+import { ModusTooltipDirective } from "shared/directives/modus-tooltip.directive";
+
+import { ReportWizardDialogPanelService } from "Reporting/dialog/services/report-wizard-dialog-panel.service";
+import {
+    REPORT_WIZARD_PROJECT_QA,
+    filterCheckboxGainsightId,
+    otherProjectCheckboxGainsightId,
+} from "./report-wizard-project-qa";
+
+/** Extended project with IsSelected for binding */
+export interface ProjectRow extends ProjectLite {
+    IsSelected: boolean;
+    DisplayProjectName: string;
+    WorkflowStateLabel: string;
+}
+
+@Component({
+    selector: "report-wizard-project",
+    standalone: true,
+    imports: [CommonModule, FormsModule, GainsightIdDirective, ModusButtonComponent, ModusTooltipDirective],
+    templateUrl: "./report-wizard-project.component.html",
+    styleUrls: ["./report-wizard-project.component.css"],
+    changeDetection: ChangeDetectionStrategy.OnPush,
+})
+export class ReportWizardProjectComponent extends BaseComponent implements OnInit {
+    public readonly tableType = input.required<number>();
+    public readonly currentProjectId = input.required<number>();
+    public readonly currentProjectName = input<string>("");
+    public readonly projectColumnCaption = input<string>("");
+    public readonly showComponent = input<boolean>(true);
+    public readonly selectAllLabel = input<string>("");
+    public readonly clearButtonLabel = input<string>("");
+    public readonly filterTooltipLabel = input<string>("");
+    /** From parent `GetComponentSettings` (`ReportWizardConfig.accessibleProjects`); same data as legacy `GetUsersProjectsWithAccessToTableType`. */
+    public readonly accessibleProjects = input<ProjectLite[]>([]);
+
+    /** Selected project IDs (output for parent) */
+    public readonly selectedProjectIds = model<number[]>([]);
+
+    protected readonly projects = signal<ProjectRow[]>([]);
+    protected readonly filterOptions = signal<string[]>([]);
+    /** Collapsed by default; current project row stays visible, other projects expand on toggle */
+    protected readonly expanded = signal(false);
+    protected readonly filterPopupVisible = signal(false);
+
+    /** Lets parent dialog relax overflow:hidden so the filter menu is not clipped (Clear row). */
+    @HostBinding("class.filter-popup-open")
+    protected get hostFilterPopupOpen(): boolean {
+        return this.filterPopupVisible();
+    }
+
+    /** Workflow state names that are currently active in the filter (checked) */
+    protected readonly activeFilters = signal<Set<string>>(new Set());
+    protected readonly nomenclature = computed<ReportWizardProjectNomenclature>(() => ({
+        selectAll: this.normalizeStringValue(this.selectAllLabel()),
+        clearButton: this.normalizeStringValue(this.clearButtonLabel()),
+        filterTooltip: this.normalizeStringValue(this.filterTooltipLabel()),
+    }));
+    protected readonly projectColumnCaptionText = computed(() => this.normalizeStringValue(this.projectColumnCaption()));
+    protected readonly currentProjectNameText = computed(() => this.normalizeStringValue(this.currentProjectName()));
+
+    /**
+     * Label for the fixed "current context" row. When Settings.ProjectName is missing (e.g. portfolio shell),
+     * fall back to project id so the row is not blank; hide the row when there is no current project at all.
+     */
+    protected readonly currentProjectRowLabel = computed(() => {
+        const name = this.currentProjectNameText();
+        if (name) {
+            return name;
+        }
+        const id = this.currentProjectId();
+        return id > 0 ? String(id) : "";
+    });
+
+    protected readonly showCurrentProjectRow = computed(() => this.currentProjectRowLabel().length > 0);
+
+    /** Same id map as the template; exported for Gainsight + colocated `*.spec.ts` queries. */
+    protected readonly reportWizardProjectQa = REPORT_WIZARD_PROJECT_QA;
+
+    /** Template helpers for stable workflow-filter / row checkbox ids (see `report-wizard-project-qa.ts`). */
+    protected readonly filterCheckboxGainsightId = filterCheckboxGainsightId;
+    protected readonly otherProjectCheckboxGainsightId = otherProjectCheckboxGainsightId;
+
+    private readonly _injector = inject(Injector);
+    private readonly _panelService = inject(ReportWizardDialogPanelService);
+
+    @ViewChild("projectFilterRoot", { read: ElementRef })
+    private readonly _projectFilterRoot?: ElementRef<HTMLElement>;
+
+    constructor() {
+        super();
+    }
+
+    public ngOnInit(): void {
+        const opts = { injector: this._injector };
+        this.subscribeTo(
+            combineLatest([
+                toObservable(this.tableType, opts),
+                toObservable(this.showComponent, opts),
+                toObservable(this.accessibleProjects, opts),
+                toObservable(this.currentProjectId, opts),
+            ]).pipe(
+                filter(([tt, show]) => !!tt && show)
+            ),
+            () => this.applyProjectsFromConfig()
+        );
+        this.subscribeTo(this._panelService.resetPanelsEvent, this.resetProjectPanelToInitialState.bind(this));
+    }
+
+    /** Collapsed list + filter closed; report-wizard-dialog requests reset via {@link ReportWizardDialogPanelService}. */
+    public resetProjectPanelToInitialState(): void {
+        this.expanded.set(false);
+        this.filterPopupVisible.set(false);
+    }
+
+    /**
+     * Builds rows from {@link accessibleProjects} (server list for the wizard table type):
+     * 1. Excludes the current project (already shown in the fixed header row).
+     * 2. Maps rows to {@link ProjectRow} with normalized display strings.
+     * 3. Derives unique sorted workflow labels for the filter checkboxes.
+     * 4. Pre-checks all filter options so the "other projects" list starts fully visible.
+     */
+    private applyProjectsFromConfig(): void {
+        const result = this.accessibleProjects();
+        const currentId = this.currentProjectId();
+        const rows: ProjectRow[] = (result || [])
+            .filter((project) => project.ProjectID !== currentId)
+            .map((project) => ({
+                ...project,
+                IsSelected: project.IsSelected ?? false,
+                DisplayProjectName: this.normalizeStringValue((project as any).ProjectName),
+                WorkflowStateLabel: this.normalizeStringValue((project as any).WorkflowStateName),
+            }));
+        this.projects.set(rows);
+        const unique = [...new Set(rows.map((row) => row.WorkflowStateLabel).filter(Boolean))].sort();
+        this.filterOptions.set(unique);
+        this.activeFilters.set(new Set(unique));
+        this.emitSelectedIds();
+    }
+
+    /** Checked workflow filters are additive; none checked => only the default (current) project row is shown.
+     * When there are no workflow labels to filter on, every loaded "other" project row is visible (matches legacy when SP omits state names).
+     */
+    protected readonly visibleProjects = computed(() => {
+        const all = this.projects();
+        const filters = this.activeFilters();
+        const optionLabels = this.filterOptions();
+        if (optionLabels.length === 0) {
+            return all;
+        }
+        if (filters.size === 0) {
+            return [];
+        }
+        return all.filter((project) => filters.has(project.WorkflowStateLabel));
+    });
+
+    protected readonly isSelectAllChecked = computed(() => {
+        const visible = this.visibleProjects();
+        if (visible.length === 0) {
+            return false;
+        }
+        return visible.every((project) => project.IsSelected);
+    });
+
+    protected toggleExpand(): void {
+        this.expanded.update((v) => !v);
+    }
+
+    protected toggleFilterPopup(): void {
+        this.filterPopupVisible.update((v) => !v);
+    }
+
+    @HostListener("document:click", ["$event"])
+    protected onDocumentClick(event: MouseEvent): void {
+        if (!this.filterPopupVisible()) {
+            return;
+        }
+        const root = this._projectFilterRoot?.nativeElement;
+        const target = event.target;
+        if (root && target instanceof Node && root.contains(target)) {
+            return;
+        }
+        this.filterPopupVisible.set(false);
+    }
+
+    protected onFilterCheckboxChange(option: string, checked: boolean): void {
+        this.activeFilters.update((set) => {
+            const next = new Set(set);
+            if (checked) {
+                next.add(option);
+            } else {
+                next.delete(option);
+            }
+            return next;
+        });
+    }
+
+    /**
+     * ReportingWizard.aspx: Clear unchecks every filter checkbox; list then shows only the default project
+     * until the user checks workflow filters again ({@link visibleProjects}).
+     */
+    protected onClearFilters(event?: Event): void {
+        event?.stopPropagation();
+        event?.preventDefault();
+        this.activeFilters.set(new Set());
+        this.filterPopupVisible.set(false);
+    }
+
+    protected onSelectAllChange(checked: boolean): void {
+        const visible = this.visibleProjects();
+        // Only flip selection for rows that match the active workflow filter; off-filter rows keep their previous IsSelected.
+        this.projects.update((rows) =>
+            rows.map((row) => ({
+                ...row,
+                IsSelected: visible.some((visibleProject) => visibleProject.ProjectID === row.ProjectID) ? checked : row.IsSelected,
+            }))
+        );
+        this.emitSelectedIds();
+    }
+
+    protected onProjectSelectionChange(project: ProjectRow, checked: boolean): void {
+        this.projects.update((rows) =>
+            rows.map((row) =>
+                row.ProjectID === project.ProjectID ? { ...row, IsSelected: checked } : row
+            )
+        );
+        this.emitSelectedIds();
+    }
+
+    private emitSelectedIds(): void {
+        const ids = this.projects()
+            .filter((project) => project.IsSelected)
+            .map((project) => project.ProjectID);
+        this.selectedProjectIds.set(ids);
+    }
+
+    private normalizeStringValue(value: unknown): string {
+        if (typeof value === "string") {
+            return value;
+        }
+
+        if (!value) {
+            return "";
+        }
+
+        if (typeof value === "object") {
+            const normalized = value as Record<string, unknown>;
+            const candidate = normalized["DisplayDescription"] ?? normalized["Name"] ?? normalized["Value"];
+            if (typeof candidate === "string") {
+                return candidate;
+            }
+        }
+
+        return `${value}`;
+    }
+
+    /** Called from parent to sync selected count — projects component owns the state */
+    public getSelectedProjectIds(): number[] {
+        return this.projects()
+            .filter((project) => project.IsSelected)
+            .map((project) => project.ProjectID);
+    }
+}
+
+export interface ReportWizardProjectNomenclature {
+    selectAll: string;
+    clearButton: string;
+    filterTooltip: string;
+}
