+import { ComponentTypes } from "shared/enums/ComponentTypes";
+import { ReportingOptions } from "./ReportingOptions";
+import { PrologTableTypes } from "shared/enums/PrologTableTypes";
+
+export class ReportWizardLoadArgs {
+    public readonly targetComponentType = ComponentTypes.ReportWizard;
+    public readonly keyValues: string;
+    public readonly options: ReportingOptions;
+    public readonly tableType: PrologTableTypes;
+    public readonly isForMultipleRecords: boolean;
+    /** Actual child table type override from querystring (ChildRecordType), if provided. */
+    public readonly actualTableType: number;
+    /** When true, show the project selection list (for multi-record reports when table type is project-scoped) */
+    public readonly showProjectSelection: boolean;
+    /** Project ID from the calling legacy page (0 = portfolio scope). Undefined when called from Angular. */
+    public readonly callerProjectId?: number;
+
+    constructor(
+        keyValues: string,
+        options: ReportingOptions,
+        tableType: PrologTableTypes,
+        isForMultipleRecords: boolean,
+        actualTableType: number,
+        showProjectSelection: boolean,
+        callerProjectId?: number
+    ) {
+        this.keyValues = keyValues;
