+describe("installReportingWizardBridge", () => {
+    let targetWindow: Window & { AngularReportingWizard?: { open: Mock } };
+    let topWindow: Window & { AngularReportingWizard?: { open: Mock } };
+    let ngZoneRun: Mock;
+    let dialogOpen: Mock;
+    let injector: Injector;
+
+    beforeEach(() => {
+        targetWindow = {} as Window & { AngularReportingWizard?: { open: Mock } };
+        topWindow = {} as Window & { AngularReportingWizard?: { open: Mock } };
+        ngZoneRun = vi.fn((fn: () => void) => fn());
+        dialogOpen = vi.fn().mockResolvedValue(true);
+        const dialogService = { open: dialogOpen } as unknown as ReportWizardDialogService;
+        const applicationContext = { injector: {} as Injector };
+        const exceptionService = {
+            logError: vi.fn(),
+            logException: vi.fn(),
+        };
+        injector = {
+            get: vi.fn((token: unknown) => {
+                if (token === wemiExceptionService) {
+                    return exceptionService;
+                }
+                if (token === ApplicationContextService) {
+                    return applicationContext;
+                }
+                throw new Error(`Unexpected token: ${String(token)}`);
+            }),
+        } as unknown as Injector;
+        const ngZone = { run: ngZoneRun } as unknown as NgZone;
+
+        installReportingWizardBridge(targetWindow, ngZone, dialogService, injector);
+    });
+
+    it("assigns bridge only to targetWindow, not window.top", () => {
+        expect(targetWindow.AngularReportingWizard).toBeDefined();
+        expect(topWindow.AngularReportingWizard).toBeUndefined();
+    });
+
+    it("bridge.open runs in NgZone and forwards to ReportWizardDialogService.open", async () => {
+        const opts = new ReportingOptions();
+        const successCallback = vi.fn();
+        const queryString = "?FRTY=1";
+
+        targetWindow.AngularReportingWizard!.open(queryString, "1,2", opts, successCallback, 42);
+
+        expect(ngZoneRun).toHaveBeenCalledTimes(1);
+        expect(dialogOpen).toHaveBeenCalledTimes(1);
+        expect(dialogOpen).toHaveBeenCalledWith(
+            "1,2",
+            opts,
+            expect.any(Number),
+            expect.any(Boolean),
+            expect.any(Number),
+            expect.any(Boolean),
+            42
+        );
+        await vi.waitFor(() => expect(successCallback).toHaveBeenCalled());
+    });
+
+    it("logs error when opts is null", () => {
+        const exceptionService = (injector.get as Mock)(wemiExceptionService);
+        targetWindow.AngularReportingWizard!.open("?FRTY=1", "", null as unknown as ReportingOptions, vi.fn());
+        expect(exceptionService.logError).toHaveBeenCalled();
+        expect(dialogOpen).not.toHaveBeenCalled();
+    });
+
+    describe("Legacy host entry paths (PS-67831)", () => {
+        it("DataViews-style list open forwards multi-record params and DailyReport filters", async () => {
+            const opts = new ReportingOptions();
+            opts.PrintingVisibleItems = true;
+            targetWindow.AngularReportingWizard!.open(
+                "?FRTY=8&FRLIST=1&comids=5&locids=9",
+                "1,2",
+                opts,
+                vi.fn()
+            );
+            expect(dialogOpen).toHaveBeenCalledWith(
+                "1,2",
+                expect.objectContaining({
+                    PrintingVisibleItems: true,
+                    AdditionalDataFilters: { "@CompanyIDs": "5", "@LocationIDs": "9" },
+                }),
+                expect.any(Number),
+                true,
+                expect.any(Number),
+                true,
+                undefined
+            );
+        });
+
+        it("FormManager-style single-record open parses FRID into keyValues", () => {
+            const opts = new ReportingOptions();
+            targetWindow.AngularReportingWizard!.open("?FRTY=8&FRID=77", "", opts, vi.fn());
+            expect(dialogOpen).toHaveBeenCalledWith(
+                "77",
+                opts,
+                expect.any(Number),
+                false,
+                expect.any(Number),
+                false,
+                undefined
+            );
+        });
+    });
+});
+
+describe("fdefPageTypeHasLocalModalHost", () => {
+    it("returns true for fdef page types with modal-host", () => {
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.MeetingMinutes)).toBe(true);
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.Checklist)).toBe(true);
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.Transmittal)).toBe(true);
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.SubmittalPackage)).toBe(true);
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.Drawing)).toBe(true);
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.SpecSection)).toBe(true);
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.SpecSet)).toBe(true);
+    });
+
+    it("returns false for other page types", () => {
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.RFI)).toBe(false);
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.Budget)).toBe(false);
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.Project)).toBe(false);
+        expect(fdefPageTypeHasLocalModalHost(PageTypes.None)).toBe(false);
+    });
+});
