+     */
+    buildReportRequest(state: ReportActionState, action: ReportActionValue): ReportRequest {
+        const request: ReportRequest = {
+            TableType: state.options?.actualTableType || state.tableType,
+            PrimaryKey: 0,
+            Action: action,
+            RecordOption: state.recordOption,
+            ReportID: state.reportId,
+            Subject: state.subject,
+            FileName: state.fileName,
+            Format: state.format,
+            Body: state.body,
+            Attachments: state.recordOption === RECORD_OPTIONS.Single ? state.attachments : null,
+            IncludeFileNamesInHeaders: state.includeFileNamesInHeaders,
+            Contacts: state.contacts?.length ? state.contacts : null,
+            SelectedPrimaryKeys: state.keyValues,
+            Behavior: state.behavior,
+            AdditionalProjectIds: null,
+            AdditionalProjectFilters: null,
+            AdHocColumns: null,
+            AdHocViewId: 0,
+            AdHocViewName: null,
+            AdHocPreviewViewName: null,
+            AdHocPrintingSelectedItems: false,
+            AdHocOriginalSelectedPrimaryKeys: null,
+            AdHocFilterArea: 0,
+            AdhocPreviewElements: null,
+            OkToUseDisabledReport: false,
+            ServerPrefix: null,
+            Identity: null,
+            AdditionalDataFilters: {},
+            MeetingInvitationSubject: null,
+            Record: null,
+        };
+
+        if (state.isAdHocReport) {
+            request.ReportID = ADHOC_REPORT_IDENTIFIER;
+            request.AdHocViewId = state.adHocViewId;
+            request.AdHocViewName = String(state.adHocViewId);
+            request.RecordOption = RECORD_OPTIONS.MultipleOneFileWithoutAttachments;
+            request.AdHocPrintingSelectedItems = !state.options?.printingVisibleItems;
+
+            if (state.adHocViewId === state.options?.currentViewId) {
+                request.AdHocColumns = this.getVisibleAdHocColumns(
+                    state.options?.columns ?? [],
+                    state.options?.defaultGroup ?? "",
+                    state.options?.defaultSort ?? "",
+                    !!state.options?.fromAngular
+                );
+            }
+
+            if (window.parent && typeof window.parent["m_adHocFilterArea"] !== "undefined") {
+                request.AdHocFilterArea = window.parent["m_adHocFilterArea"] as number;
+            }
+        }
+
+        if (state.behavior === REPORT_BEHAVIORS.None && state.selectedProjectIds?.length) {
+            request.AdditionalProjectIds = state.selectedProjectIds;
+            if (state.options?.filters?.length) {
+                request.AdditionalProjectFilters = state.options.filters as never;
+            }
+        }
+
+        if (state.additionalDataFilters && Object.keys(state.additionalDataFilters).length > 0) {
+            request.AdditionalDataFilters = state.additionalDataFilters;
+        }
+
+        // Server SetupSingleRecordReportRequestAsync uses request.PrimaryKey (not SelectedPrimaryKeys) for scope.
+        if (request.RecordOption === RECORD_OPTIONS.Single && state.keyValues) {
+            const firstSegment = state.keyValues.split(",")[0]?.trim() ?? "";
+            const pk = parseInt(firstSegment, 10);
+            if (!Number.isNaN(pk) && pk > 0) {
+                request.PrimaryKey = pk;
+            }
+        }
+
+        return request;
+    }
+
+    /**
+     * Flattens To/Cc/Bcc rows into report-request contacts with EmailType set per bucket.
+     * Used when assembling {@link ReportRequest.Contacts} (via panel service request/response).
+     */
+    buildEmailContactsForReportRequest(
+        tos: ContactForPicklist[],
+        ccs: ContactForPicklist[],
+        bccs: ContactForPicklist[],
+    ): ContactForPicklist[] {
+        const selectedContacts: ContactForPicklist[] = [];
+        const buckets: [ContactForPicklist[], EMailTypes][] = [
+            [tos, EMailTypes.To],
+            [ccs, EMailTypes.CC],
+            [bccs, EMailTypes.BCC],
+        ];
+        for (const [list, type] of buckets) {
+            for (const contact of list) {
+                contact.EmailType = type;
+                selectedContacts.push(contact);
+            }
+        }
+        return selectedContacts;
+    }
+
+    /**
+     * Flattens recipient rows for submit. Returns an empty array when no recipients are selected
+     * (caller shows nomenclature error).
+     */
+    collectValidatedEmailContacts(
+        tos: ContactForPicklist[],
+        ccs: ContactForPicklist[],
+        bccs: ContactForPicklist[],
+    ): ContactForPicklist[] {
+        return this.buildEmailContactsForReportRequest(tos, ccs, bccs);
+    }
+
+    /**
+     * Validates state and contacts. Returns error message or null if valid.
+     */
+    validateBeforeInitiate(
+        state: ReportActionState,
+        action: ReportActionValue,
+        nomenclature: ReportWizardNomenclature,
+        validateContacts: () => boolean
+    ): string | null {
+        if (!state.isAdHocReport && state.behavior !== REPORT_BEHAVIORS.MeetingSendInvitation && !state.reportId) {
+            return nomenclature.mustSelectReport;
+        }
+        if (action === REPORT_ACTION.Email && !validateContacts()) {
+            return nomenclature.oneRecipientRequired;
+        }
+        return null;
+    }
+
+    private getVisibleAdHocColumns(columns: any[], defaultGroup: string, defaultSort: string, fromAngular: boolean): any[] {
+        const adHocColumns: any[] = [];
+        for (let i = 0; i < columns.length; i++) {
+            const column = columns[i];
+
+            if (column.behavior === ListViewColumnBehaviors.FileIcon) {
+                continue;
+            }
+
+            let okToAdd = false;
+            if (fromAngular) {
+                okToAdd = !column.hidden && (column.width !== 0 || column.columnName === defaultGroup || column.columnName === defaultSort);
+            } else {
+                okToAdd = column.Width !== 0 || column.ColumnName === defaultGroup || column.ColumnName === defaultSort;
+            }
+            if (okToAdd) {
+                adHocColumns.push(column);
+            }
+        }
+
+        return adHocColumns;
+    }
+
+    /**
+     * Initiates the report request.
+     *
+     * For email actions: sums {@link IncludeAsTypes.Attachment} and {@link IncludeAsTypes.EmbedInReport}
+     * attachment sizes toward the email payload budget; {@link IncludeAsTypes.Link} rows do not count.
+     * If the total exceeds {@link FILES_TOO_LARGE_MB} and the user confirms, those Attachment/Embed rows
+     * are rewritten in-place to {@link IncludeAsTypes.Link} so the server emails links instead of embedding bytes.
+     */
+    async initiateReport(
+        request: ReportRequest,
+        action: ReportActionValue,
+        nomenclature: ReportWizardNomenclature,
+        onClose: () => void,
+        state: ReportActionState
+    ): Promise<void> {
+        if (action === REPORT_ACTION.Email && request.Attachments?.length) {
+            const attachments = request.Attachments as { IncludeAs?: number; FileSize?: number }[];
+            const sizeMb = attachments.reduce((sum: number, attachment) => {
+                if (attachment.IncludeAs === IncludeAsTypes.Attachment || attachment.IncludeAs === IncludeAsTypes.EmbedInReport) {
+                    return sum + (attachment.FileSize ?? 0);
+                }
+                return sum;
+            }, 0) / 1048576;
+
+            if (sizeMb > FILES_TOO_LARGE_MB) {
+                const doInitiate = await this.wemiConfirmAsync({
+                    content: nomenclature.filesTooLargeMessage,
+                    confirmText: nomenclature.filesTooLargeSendButton,
+                    cancelText: nomenclature.filesTooLargeCancelButton,
+                });
+                if (!doInitiate) {
+                    return;
+                }
+
+                attachments.forEach((attachment) => {
+                    if (attachment.IncludeAs === IncludeAsTypes.Attachment || attachment.IncludeAs === IncludeAsTypes.EmbedInReport) {
+                        attachment.IncludeAs = IncludeAsTypes.Link;
+                    }
+                });
+            }
+        }
+
+        if (
+            action === REPORT_ACTION.FileLibrary &&
+            request.AdditionalProjectIds?.length &&
+            nomenclature.multiProjectFileLibraryTitle
+        ) {
+            const doInitiate = await this.wemiConfirmAsync({
+                title: nomenclature.multiProjectFileLibraryTitle,
+                content: nomenclature.multiProjectFileLibraryText,
+                confirmText: nomenclature.multiProjectFileLibraryYes,
+                cancelText: nomenclature.multiProjectFileLibraryNo,
+                defaultButton: PromptButtonTypes.Cancel,
+            });
+            if (!doInitiate) {
+                return;
+            }
+        }
+
+        try {
+            const fileRequestId = await this._reportSystem.InitiateReportRequest(request);
+
+            const downloadAction =
+                action === REPORT_ACTION.View
+                    ? DownloadModuleActionTypes.View
+                    : action === REPORT_ACTION.FileLibrary
+                      ? (state.isForMultipleRecords ? DownloadModuleActionTypes.Download : DownloadModuleActionTypes.View)
+                      : DownloadModuleActionTypes.Download;
+
+            this.openMonitorWindow(fileRequestId as number, DownloadModuleTypes.Report, downloadAction);
+            onClose();
+        } catch (reason) {
+            this.wemiException.handlePromiseCatch(reason);
+        }
+    }
+
+    private wemiConfirmAsync(settings: Partial<PromptSettings>): Promise<boolean> {
+        return new Promise((resolve) => {
+            this._currentContext.confirmationModule.wemiConfirm(
+                new PromptSettings({
+                    ...settings,
+                    northstarStyle: true,
+                    confirm: () => resolve(true),
+                    cancel: () => resolve(false),
+                })
+            );
+        });
+    }
+
+    private openMonitorWindow(fileRequestId: number, type: DownloadModuleTypes, actionType: DownloadModuleActionTypes): void {
+        const url = `${Common.getRequestApplicationPath()}DMS/Downloads/Monitor.aspx?PKID=${fileRequestId}&Typ=${type}&Act=${actionType}&orgid=${this._currentContext.OrganizationId}`;
+        window.open(url, "_blank", "height=200, width=450, status=yes, resizable=no, scrollbars=no, menubar=no, toolbar=no, location=no");
+    }
+}
