+import { TestBed } from "@angular/core/testing";
+import { expect } from "vitest";
+
+import { ContactForPicklist } from "shared/classes/Lookups/ContactForPicklist";
+import { CurrentContextService } from "shared/services/CurrentContextService";
+import { createMockCurrentContext } from "shared/testing/mock-current-context";
+
+import { ReportWizardDialogPanelService } from "./report-wizard-dialog-panel.service";
+
+function makeContact(id: number): ContactForPicklist {
+    const contact = new ContactForPicklist();
+    contact.ContactID = id;
+    contact.Email = `user${id}@example.com`;
+    return contact;
+}
+
+describe("ReportWizardDialogPanelService", () => {
+    let service: ReportWizardDialogPanelService;
+
+    beforeEach(() => {
+        TestBed.resetTestingModule();
+        TestBed.configureTestingModule({
+            providers: [
+                ReportWizardDialogPanelService,
+                { provide: CurrentContextService, useValue: createMockCurrentContext() },
+            ],
+        });
+        service = TestBed.inject(ReportWizardDialogPanelService);
+    });
+
+    it("resolves with contacts when complete follows a single request", async () => {
+        const contacts = [makeContact(1)];
+        service.requestValidatedEmailContactsEvent.subscribe(() => {
+            service.completeValidatedEmailContacts(contacts);
+        });
+
+        await expect(service.requestValidatedEmailContacts()).resolves.toBe(contacts);
+    });
+
+    it("resolves with null when complete passes null", async () => {
+        service.requestValidatedEmailContactsEvent.subscribe(() => {
+            service.completeValidatedEmailContacts(null);
+        });
+
+        await expect(service.requestValidatedEmailContacts()).resolves.toBeNull();
+    });
+
+    it("resolves superseded request with null when a second request starts before complete", async () => {
+        const contacts = [makeContact(2)];
+        let eventCount = 0;
+
+        service.requestValidatedEmailContactsEvent.subscribe(() => {
+            eventCount++;
+            if (eventCount === 2) {
+                service.completeValidatedEmailContacts(contacts);
+            }
+        });
+
+        const first = service.requestValidatedEmailContacts();
+        const second = service.requestValidatedEmailContacts();
+
+        await expect(first).resolves.toBeNull();
+        await expect(second).resolves.toBe(contacts);
+    });
+
+    it("does not throw when complete is called with no pending request", () => {
+        expect(() => service.completeValidatedEmailContacts(null)).not.toThrow();
+        expect(() => service.completeValidatedEmailContacts([makeContact(3)])).not.toThrow();
+    });
+});
