+import { Injectable } from "@angular/core";
+import { Subject } from "rxjs";
+import { BaseService } from "shared/services/BaseService";
+import { ContactForPicklist } from "shared/classes/Lookups/ContactForPicklist";
+
+/**
+ * Dialog-scoped **transport** between {@link ReportWizardDialogComponent} and child panels
+ * (project list, email recipients): reset signals and validated-email request/response promises.
+ *
+ * No domain rules here (no EmailType flattening, no ReportRequest shaping) — use
+ * {@link ReportWizardLogicService} for that.
+ */
+@Injectable()
+export class ReportWizardDialogPanelService extends BaseService {
+    private readonly _resetPanelsSubject = new Subject<void>();
+    public readonly resetPanelsEvent = this._resetPanelsSubject.asObservable();
+
+    private readonly _requestValidatedEmailContactsSubject = new Subject<void>();
+    public readonly requestValidatedEmailContactsEvent = this._requestValidatedEmailContactsSubject.asObservable();
+
+    private _validatedEmailContactsResolve: ((contacts: ContactForPicklist[] | null) => void) | null = null;
+
+    public requestPanelReset(): void {
+        this._resetPanelsSubject.next();
+    }
+
+    /**
+     * Dialog requests validated To/Cc/Bcc; email-selector responds via {@link completeValidatedEmailContacts}.
+     * A new call resolves any in-flight request with `null` (superseded).
+     */
+    public requestValidatedEmailContacts(): Promise<ContactForPicklist[] | null> {
+        return new Promise((resolve) => {
+            this._validatedEmailContactsResolve?.(null);
+            this._validatedEmailContactsResolve = resolve;
+            this._requestValidatedEmailContactsSubject.next();
+        });
+    }
+
+    public completeValidatedEmailContacts(contacts: ContactForPicklist[] | null): void {
+        const resolve = this._validatedEmailContactsResolve;
+        this._validatedEmailContactsResolve = null;
+        resolve?.(contacts);
+    }
+}
