+/* eslint-disable @typescript-eslint/no-explicit-any */
+import { Injector, signal } from "@angular/core";
+import { TestBed } from "@angular/core/testing";
+import { vi } from "vitest";
+
+import { ReportingOptions } from "Reporting/dialog/models/ReportingOptions";
+import { ModalContent, ModalHostService } from "shared/components/modal-host/modal-host.service";
+import { PrologTableTypes } from "shared/enums/PrologTableTypes";
+import { ApplicationContextService } from "shared/services/ApplicationContextService";
+import { CurrentContextService } from "shared/services/CurrentContextService";
+import { wemiExceptionService } from "shared/support/wemiExceptionService";
+
+import { buildReportWizardOpenParams } from "../models/report-wizard-open-params";
+import { ReportWizardDialogComponent } from "../components/report-wizard-dialog/report-wizard-dialog.component";
+import { ReportWizardDialogService } from "./report-wizard-dialog.service";
+
+/**
+ * Pure helper `buildReportWizardOpenParams` — no TestBed (see angular-unit-testing.md, service vs pure).
+ */
+describe("buildReportWizardOpenParams", () => {
+    function makeOptions(over: Partial<ReportingOptions> = {}): ReportingOptions {
+        const o = new ReportingOptions();
+        o.PrintingVisibleItems = false;
+        o.CurrentViewId = 0;
+        o.ViewId = 0;
+        o.SpecificAdHocViewRequested = false;
+        o.DefaultGroup = "";
+        o.DefaultSort = "";
+        o.FromAngular = false;
+        Object.assign(o, over);
+        return o;
+    }
+
+    it("parses table type from FRTY and list mode from FRLIST", () => {
+        const options = makeOptions();
+        const result = buildReportWizardOpenParams(
+            "?FRTY=8&FRLIST=1",
+            "1,2",
+            options,
+            PrologTableTypes.None
+        );
+        expect(result.tableType).toBe(PrologTableTypes.RFI);
+        expect(result.isForMultipleRecords).toBe(true);
+        expect(result.keyValues).toBe("1,2");
+    });
+
+    it("uses fallback table type when FRTY is absent", () => {
+        const options = makeOptions();
+        const result = buildReportWizardOpenParams("", "", options, PrologTableTypes.Address);
+        expect(result.tableType).toBe(PrologTableTypes.Address);
+    });
+
+    it("sets keyValues to -1 for multi-select when keyValues empty and PrintingVisibleItems is true", () => {
+        const options = makeOptions({ PrintingVisibleItems: true });
+        const result = buildReportWizardOpenParams("?FRLIST=1", "", options, PrologTableTypes.RFI);
+        expect(result.keyValues).toBe("-1");
+    });
+
+    it("returns showProjectSelection false when PrintingVisibleItems is false", () => {
+        const options = makeOptions({ PrintingVisibleItems: false });
+        const result = buildReportWizardOpenParams("?FRLIST=1&FRTY=8", "", options, PrologTableTypes.RFI);
+        expect(result.showProjectSelection).toBe(false);
+    });
+
+    it("passes callerProjectId through", () => {
+        const options = makeOptions();
+        const result = buildReportWizardOpenParams("", "k", options, 1, 999);
+        expect(result.callerProjectId).toBe(999);
+    });
+
+    describe("Regression matrix entry paths (PS-67831)", () => {
+        it("parses single-record FRID when not in list mode", () => {
+            const options = makeOptions();
+            const result = buildReportWizardOpenParams("?FRTY=8&FRID=42", "", options, PrologTableTypes.None);
+            expect(result.isForMultipleRecords).toBe(false);
+            expect(result.keyValues).toBe("42");
+        });
+
+        it("maps DailyReport comids and locids query params to AdditionalDataFilters", () => {
+            const options = makeOptions();
+            buildReportWizardOpenParams(
+                "?FRTY=8&FRLIST=1&comids=10,11&locids=20",
+                "1,2",
+                options,
+                PrologTableTypes.DailyReport
+            );
+            expect(options.AdditionalDataFilters).toEqual({
+                "@CompanyIDs": "10,11",
+                "@LocationIDs": "20",
+            });
+        });
+
+        it("applies ReportWizardBehavior from BEHAVIOR query param", () => {
+            const options = makeOptions();
+            buildReportWizardOpenParams("?FRTY=8&BEHAVIOR=2", "1", options, PrologTableTypes.RFI);
+            expect(options.Behavior).toBe(2);
+        });
+
+        it("enables showProjectSelection for multi-record visible-items RFI", () => {
+            const options = makeOptions({ PrintingVisibleItems: true });
+            const result = buildReportWizardOpenParams("?FRTY=8&FRLIST=1", "", options, PrologTableTypes.RFI);
+            expect(result.showProjectSelection).toBe(true);
+            expect(result.keyValues).toBe("-1");
+        });
+    });
+});
+
+/**
+ * Regression suite for the per-open close handler. The earlier implementation stored
+ * the resolver on a mutable instance field (`_resolveClose`), so a stale `closedEvent`
+ * from a superseded wizard could resolve the most recent `open()` promise — see the
+ * PR review on `runOpen`. The fix subscribes via `take(1)` and closes over `req` /
+ * `generation` locally, so each subscription only ever resolves its own promise.
+ */
+describe("ReportWizardDialogService - open/close race", () => {
+    let service: ReportWizardDialogService;
+    let activeContent: ReturnType<typeof signal<ModalContent | null>>;
+    let lastShownContent: ModalContent | null;
+    let modalHost: {
+        activeContent: typeof activeContent;
+        show: ReturnType<typeof vi.fn>;
+        close: ReturnType<typeof vi.fn>;
+        requestLoad: ReturnType<typeof vi.fn>;
+    };
+
+    function makeMockContext(): any {
+        // ModalContent ctor reads these and uses `injector` as a parent for `Injector.create`.
+        // Leaving it undefined makes Angular default to the NullInjector, which is fine
+        // because neither the test nor the service ever calls `get()` on that child injector.
+        return {
+            pageType: 0,
+            TableType: 0,
+            PrimaryKeyFieldName: "",
+            injector: undefined,
+            setPageType: vi.fn(),
+            setTableType: vi.fn(),
+            setPrimaryKeyFieldName: vi.fn(),
+        };
+    }
+
+    function openWizard(): Promise<boolean | undefined> {
+        return service.open("1", new ReportingOptions(), PrologTableTypes.RFI, false, 0, false);
+    }
+
+    beforeEach(() => {
+        TestBed.resetTestingModule();
+
+        const mockContext = makeMockContext();
+        // Standalone host injector — no parent. The service only ever asks for
+        // CurrentContextService (returned here) and SelectContactPopoverService with a
+        // null default (NullInjector returns null).
+        const hostInjector = Injector.create({
+            providers: [{ provide: CurrentContextService, useValue: mockContext }],
+        });
+
+        activeContent = signal<ModalContent | null>(null);
+        lastShownContent = null;
+        modalHost = {
+            activeContent,
+            show: vi.fn((content: ModalContent) => {
+                lastShownContent = content;
+                activeContent.set(content);
+            }),
+            // Mirrors the real ModalHostService behavior we care about: fire the active
+            // settings' closedEvent then drop the active reference.
+            close: vi.fn((result?: any) => {
+                const current = activeContent();
+                if (current) {
+                    current.settings.requestClose(result);
+                }
+                activeContent.set(null);
+            }),
+            requestLoad: vi.fn(),
+        };
+
+        TestBed.configureTestingModule({
+            providers: [
+                ReportWizardDialogService,
+                { provide: ModalHostService, useValue: modalHost },
+                { provide: ApplicationContextService, useValue: { injector: hostInjector } },
+                { provide: wemiExceptionService, useValue: { handlePromiseCatch: vi.fn() } },
+            ],
+        });
+        service = TestBed.inject(ReportWizardDialogService);
+    });
+
+    it("does not resolve a newer open() promise when an older closedEvent fires after the wizard is superseded", async () => {
+        const promiseA = openWizard();
+        const contentA = lastShownContent;
+        expect(contentA).toBeTruthy();
+
+        // Stack a non-wizard modal on top so `open()`s self-close guard skips close().
+        // This is the exact scenario where the original mutable `_resolveClose` field
+        // would be overwritten by the second open() without firing settings A first.
+        activeContent.set({ settings: { targetComponentType: -1 } } as unknown as ModalContent);
+
+        const promiseB = openWizard();
+        const contentB = lastShownContent;
+        expect(contentB).not.toBe(contentA);
+
+        let aResolved = false;
+        let aResult: boolean | undefined = true;
+        let bResolved = false;
+        let bResult: boolean | undefined = undefined;
+        promiseA.then((r) => { aResolved = true; aResult = r; });
+        promiseB.then((r) => { bResolved = true; bResult = r; });
+
+        // Fire A's closedEvent. With the original bug this would resolve promise B with
+        // A's result. With the fix A's subscription is bound to A's `req` via closure and
+        // resolves promise A as cancelled (`undefined`) on the generation-mismatch path,
+        // so the caller never hangs.
+        contentA!.settings.requestClose(true);
+        await Promise.resolve();
+        await Promise.resolve();
+
+        expect(bResolved).toBe(false);
+        expect(aResolved).toBe(true);
+        expect(aResult).toBeUndefined();
+
+        // B's own close still resolves B normally with its own result.
+        contentB!.settings.requestClose(false);
+        await Promise.resolve();
+        expect(bResolved).toBe(true);
+        expect(bResult).toBe(false);
+    });
+
+    it("resolves each open()'s promise from its own closedEvent in the serial happy path", async () => {
+        const promiseA = openWizard();
+        const contentA = lastShownContent;
+        expect(contentA).toBeTruthy();
+
+        // Close A through the modal-host path (mirrors real flow): closedEvent fires
+        // synchronously, the subscription resolves promise A with `true`.
+        service.close(true);
+        const resultA = await promiseA;
+        expect(resultA).toBe(true);
+
+        const promiseB = openWizard();
+        const contentB = lastShownContent;
+        expect(contentB).not.toBe(contentA);
+
+        service.close(false);
+        const resultB = await promiseB;
+        expect(resultB).toBe(false);
+    });
+
+    it("ignores a second emission from the same settings.closedEvent (single-fire contract)", async () => {
+        const promiseA = openWizard();
+        const contentA = lastShownContent;
+
+        contentA!.settings.requestClose(true);
+        const resultA = await promiseA;
+        expect(resultA).toBe(true);
+
+        // A second emission must not double-resolve or throw. `take(1)` has already
+        // unsubscribed; if the subject ever fired again no callback should run.
+        expect(() => contentA!.settings.requestClose(false)).not.toThrow();
+    });
+});
+
+describe("ReportWizardDialogService - open modal settings", () => {
+    let service: ReportWizardDialogService;
+    let lastShownContent: ModalContent | null;
+    let modalHost: {
+        activeContent: ReturnType<typeof signal<ModalContent | null>>;
+        show: ReturnType<typeof vi.fn>;
+        close: ReturnType<typeof vi.fn>;
+        requestLoad: ReturnType<typeof vi.fn>;
+    };
+
+    function makeMockContext(): any {
+        return {
+            pageType: 0,
+            TableType: 0,
+            PrimaryKeyFieldName: "",
+            injector: undefined,
+            setPageType: vi.fn(),
+            setTableType: vi.fn(),
+            setPrimaryKeyFieldName: vi.fn(),
+        };
+    }
+
+    function openWizard(): Promise<boolean | undefined> {
+        return service.open("1", new ReportingOptions(), PrologTableTypes.RFI, false, 0, false);
