+        });
+
+        const activeContent = signal<ModalContent | null>(null);
+        lastShownContent = null;
+        modalHost = {
+            activeContent,
+            show: vi.fn((content: ModalContent) => {
+                lastShownContent = content;
+                activeContent.set(content);
+            }),
+            close: vi.fn((result?: any) => {
+                const current = activeContent();
+                if (current) {
+                    current.settings.requestClose(result);
+                }
+                activeContent.set(null);
+            }),
+            requestLoad: vi.fn(),
+        };
+
+        TestBed.configureTestingModule({
+            providers: [
+                ReportWizardDialogService,
+                { provide: ModalHostService, useValue: modalHost },
+                { provide: ApplicationContextService, useValue: { injector: hostInjector } },
+                { provide: wemiExceptionService, useValue: { handlePromiseCatch: vi.fn() } },
+            ],
+        });
+        service = TestBed.inject(ReportWizardDialogService);
+    });
+
+    it("passes ReportWizardDialogComponent modal settings from getModalSettings on open", () => {
+        void openWizard();
+        expect(lastShownContent).toBeTruthy();
+        expect(lastShownContent!.componentTemplate).toBe(ReportWizardDialogComponent);
+
+        const settings = lastShownContent!.settings;
+        expect(settings.width()).toBe(720);
+        expect(settings.height()).toBe(600);
+        expect(settings.closeOnEscape).toBe(true);
+        expect(settings.closeOnClickOutside).toBe(false);
+        expect(settings.canMove).toBe(false);
+        expect(settings.canResize).toBe(false);
+        expect(settings.destroyOnClose).toBe(true);
+    });
+});
