+            providers: [
+                ReportingWizardWindow,
+                { provide: ReportWizardDialogService, useValue: { open: dialogOpen } },
+                {
+                    provide: CurrentContextService,
+                    useValue: createMockCurrentContext({ TableType: PrologTableTypes.RFI }),
+                },
+                { provide: WindowManagerService, useValue: {} },
+            ],
+        });
+        wizardWindow = TestBed.inject(ReportingWizardWindow);
+    });
+
+    it("OpenWithOptions forwards Angular list multi-record params to the dialog service", () => {
+        const options = new ReportingOptions();
+        options.RecordIds = [10, 20];
+        options.PrintingVisibleItems = true;
+        options.FromAngular = true;
+
+        wizardWindow.OpenWithOptions("?FRTY=8&FRLIST=1", options);
+
+        expect(dialogOpen).toHaveBeenCalledWith(
+            "10,20",
+            options,
+            PrologTableTypes.RFI,
+            true,
+            PrologTableTypes.None,
+            true
+        );
+    });
+
+    it("Open parses single-record FRID from the query string", () => {
+        wizardWindow.Open("?FRTY=8&FRID=99");
+
+        expect(dialogOpen).toHaveBeenCalledWith(
+            "99",
+            expect.any(ReportingOptions),
+            PrologTableTypes.RFI,
+            false,
+            PrologTableTypes.None,
+            false
+        );
+    });
+
+    it("Open invokes successCallback when the dialog closes with true", async () => {
+        const successCallback = vi.fn();
+        wizardWindow.Open("?FRTY=8&FRID=1", successCallback);
+        await vi.waitFor(() => expect(successCallback).toHaveBeenCalledTimes(1));
+    });
+});
