+import { ReportingOptions } from "Reporting/dialog/models/ReportingOptions";
+import { PrologTableTypes } from "shared/enums/PrologTableTypes";
+import { WindowBase } from "shared/window/WindowBase";
+import { inject, Injectable } from "@angular/core";
+import { buildReportWizardOpenParams } from "../models/report-wizard-open-params";
+import { ReportWizardDialogService } from "../services/report-wizard-dialog.service";
+
+export enum ReportingWizardBehaviors {
+    None = 0,
+    MeetingSendInvitation = 1,
+    SendTransmittal = 2,
+}
+
+@Injectable()
+export class ReportingWizardWindow extends WindowBase {
+    private m_Options: ReportingOptions;
+    private m_SuccessCallback: () => void;
+    private m_KeyValues: string;
+
+    private readonly _dialogService = inject(ReportWizardDialogService);
+
+    /**
+     * @description Options the reporting window with options already defined
+     * @param queryString
+     * @param options
+     */
+    public OpenWithOptions(queryString: string, options: ReportingOptions): void {
+        this.m_KeyValues = options.RecordIds.join(",");
+        this.m_Options = options;
+        this.m_SuccessCallback = null;
+
+        this.openCommon(queryString);
+    }
+
+    /**
+     * @description Opens the report wizard
+     * @param queryString
+     * @param keyValues
+     * @param successCallback
+     * @param printingVisibleItems
+     * @param specificViewId
+     */
+    public Open(queryString: string, successCallback?: () => void): void {
+        // Exceptions are handled by the caller
+
+        this.m_KeyValues = undefined;
+        this.m_SuccessCallback = successCallback;
+
+        this.m_Options = new ReportingOptions();
+
+        this.openCommon(queryString);
+    };
+
+    /**
+     * Shared open path for {@link Open} and {@link OpenWithOptions}.
+     * 1. Parse the legacy query string plus cached `m_Options` / `m_KeyValues` into a {@link ReportWizardOpenParams}
+     *    (e.g. table type from `?FRTY=`, list mode from `?FRLIST=`, with fallback to the route's
+     *    `CurrentContext.TableType` when `FRTY` is absent) — see {@link buildReportWizardOpenParams}.
+     * 2. Open the modus report wizard via {@link ReportWizardDialogService.open}, which mounts the dialog.
+     * 3. If the user completes the dialog with a truthy result, run `m_SuccessCallback` (set by {@link Open}).
+     *    Promise rejections are logged so the user gets a toast instead of an unhandled rejection.
+     */
+    private openCommon(queryString: string): void {
+        const openParams = buildReportWizardOpenParams(
+            queryString, this.m_KeyValues, this.m_Options,
+            this._currentContext.TableType ?? PrologTableTypes.None
+        );
+        this._dialogService
+            .open(
+                openParams.keyValues,
+                openParams.options,
+                openParams.tableType,
+                openParams.isForMultipleRecords,
+                openParams.actualTableType,
+                openParams.showProjectSelection
+            )
+            .then((result) => {
+                if (result === true && this.m_SuccessCallback) {
+                    this.m_SuccessCallback();
+                }
+            })
+            .catch((ex) => this.wemiException.logException(ex));
+    }
+}
