+.contact-input {
+    position: relative;
+    width: 100%;
+}
+
+.contact-input-field {
+    display: flex;
+    align-items: center;
+    gap: 4px;
+    min-height: 36px;
+    padding: 3px 6px 3px 8px;
+    border: 1px solid var(--neutral-gray-1);
+    border-radius: 4px;
+    background: var(--neutral-white);
+    box-sizing: border-box;
+}
+
+.contact-input-body {
+    flex: 1 1 auto;
+    min-width: 0;
+    display: flex;
+    flex-wrap: wrap;
+    align-items: center;
+    gap: 4px;
+    cursor: text;
+}
+
+.contact-input-actions {
+    flex-shrink: 0;
+    display: flex;
+    align-items: center;
+    gap: 2px;
+}
+
+.contact-input-search-tooltip-wrap {
+    display: inline-flex;
+    align-items: center;
+}
+
+/*
+ * Default .psTooltip.allow-wrapping uses width: calc(100% - 2px); this host is only as wide as the icon
+ * button, so that rule collapses a left tooltip into a narrow vertical strip. Use a readable box instead.
+ */
+:host .contact-input-search-tooltip-wrap.psTooltip.left::before {
+    max-width: min(280px, 55vw);
+    width: max-content;
+    white-space: normal;
+    text-wrap: wrap;
+    text-align: left;
+}
+
+.contact-input-text {
+    flex: 1 1 80px;
+    min-width: 80px;
+    border: none;
+    outline: none;
+    background: transparent;
+    font-size: 14px;
+    font-family: inherit;
+    padding: 2px 0;
+    line-height: 1.4;
+}
+
+/* Dropdown panel: list row chrome aligned with modus-filter / dropdown-multiselect */
+.contact-input-dropdown {
+    position: absolute;
+    top: calc(100% + 2px);
+    left: 0;
+    right: 0;
+    z-index: 10005;
+    display: flex;
+    flex-direction: column;
+    max-height: 350px;
+    background: var(--neutral-white);
+    border: 1px solid var(--neutral-gray-1);
+    border-radius: 4px;
+    box-sizing: border-box;
+}
+
+.contact-input-dropdown-scroll {
+    display: flex;
+    flex-direction: column;
+    flex: 1 1 auto;
+    min-height: 0;
+    max-height: 350px;
+    overflow-y: auto;
+}
+
+.contact-input-dropdown .list-item {
+    display: flex;
+    align-items: center;
+    cursor: pointer;
+    user-select: none;
+    padding: 4px 8px;
+    gap: 4px;
+    height: 24px;
+}
+
+.contact-input-dropdown .list-item:hover {
+    background-color: var(--neutral-gray-0);
+}
+
+.contact-input-dropdown .item-content {
+    text-overflow: ellipsis;
+    white-space: nowrap;
+    overflow: hidden !important;
+}
+
+.contact-input-dropdown .item-content-text {
+    color: var(--primary-palette-trimble-gray);
+    font-size: 12px;
+}
