+<div class="contact-input" [gainsightId]="contactInputQa.root">
+    <div class="contact-input-field">
+        <div class="contact-input-body" (click)="focusInput()">
+            @for (contact of selected(); track contact.ContactID) {
+                <modus-chip
+                    [label]="contact.DisplayName"
+                    [showRemove]="true"
+                    [clickable]="false"
+                    [size]="'xs'"
+                    (removed)="removeContact(contact)"
+                ></modus-chip>
+            }
+            <input
+                #searchInput
+                [gainsightId]="contactInputQa.searchInput"
+                type="text"
+                class="contact-input-text"
+                [value]="query()"
+                (input)="onSearchInput($event)"
+                (focus)="onFocus()"
+                (blur)="onBlur()"
+                [placeholder]="selected().length === 0 ? placeholder() : ''"
+                autocomplete="off"
+            />
+        </div>
+        <div class="contact-input-actions">
+            <modus-button
+                [gainsightId]="contactInputQa.chevronButton"
+                class="contact-input-icon-btn"
+                [type]="'button'"
+                [size]="'sm'"
+                [variant]="'borderless'"
+                [color]="'tertiary'"
+                [modusIconLeft]="'expand_more'"
+                (mousedown)="onChevronMouseDown($event)"
+                (buttonClick)="onChevronToggle()"
+            ></modus-button>
+            <span
+                class="contact-input-search-tooltip-wrap"
+                [modusTooltip]="tooltip()"
+                [tooltipPosition]="'left'"
+            >
+                <modus-button
+                    #searchActionBtn
+                    [gainsightId]="contactInputQa.searchButton"
+                    class="contact-input-icon-btn"
+                    [type]="'button'"
+                    [size]="'sm'"
+                    [variant]="'borderless'"
+                    [color]="'tertiary'"
+                    [modusIconLeft]="'search'"
+                    (mousedown)="onSearchMouseDown($event)"
+                    (buttonClick)="onSearchClick()"
+                ></modus-button>
+            </span>
+        </div>
+    </div>
+    @if (showDropdown() && filteredContacts().length > 0) {
+        <div class="contact-input-dropdown" [gainsightId]="contactInputQa.dropdown" role="listbox">
+            <div class="contact-input-dropdown-scroll ThinScrollbar">
+                @for (c of filteredContacts(); track c.ContactID) {
+                    <div
+                        class="list-item"
+                        role="option"
+                        (mousedown)="$event.preventDefault()"
+                        (click)="selectContact(c)"
+                        [title]="c.DisplayAddress || c.DisplayName"
+                    >
+                        <div class="item-content">
+                            <span class="item-content-text EllipsisOverflow">{{ c.DisplayAddress || c.DisplayName }}</span>
+                        </div>
+                    </div>
+                }
+            </div>
+        </div>
+    }
+</div>
