+import { ComponentFixture } from "@angular/core/testing";
+import { vi } from "vitest";
+
+import { ContactForPicklist, EMailTypes } from "shared/classes/Lookups/ContactForPicklist";
+import { ModusButtonComponent } from "shared/controls/modus-button/modus-button.component";
+import { configureStandalonePageTest } from "shared/testing/configure-standalone-page-test";
+
+import { ContactInputComponent } from "./contact-input.component";
+
+function makeContact(over: Partial<ContactForPicklist> = {}): ContactForPicklist {
+    const c = new ContactForPicklist();
+    c.DisplayName = "Jane Doe";
+    c.Email = "jane@example.com";
+    c.Title = "";
+    c.ContactID = 1;
+    c.CompanyName = "";
+    c.CompanyID = 0;
+    c.UserID = "";
+    c.UserDeleted = false;
+    c.ContactPicture = "";
+    c.EmailType = EMailTypes.To;
+    c.DisplayAddress = "";
+    c.Tel = "";
+    c.Cel = "";
+    Object.assign(c, over);
+    return c;
+}
+
+/**
+ * Characterization tests for ContactInputComponent.
+ * Template is stubbed (`configureStandalonePageTest` default); see angular-unit-testing.md.
+ */
+describe("ContactInputComponent", () => {
+    let fixture: ComponentFixture<ContactInputComponent>;
+    let component: ContactInputComponent;
+
+    async function setup(): Promise<void> {
+        const result = await configureStandalonePageTest(ContactInputComponent, {});
+        fixture = result.fixture;
+        component = result.component;
+        fixture.detectChanges();
+    }
+
+    beforeEach(() => {
+        vi.useFakeTimers({ shouldAdvanceTime: true });
+    });
+
+    afterEach(() => {
+        vi.useRealTimers();
+    });
+
+    describe("Business Logic", () => {
+        /** Invokes private {@link ContactInputComponent.applyFilter}. */
+        function applyFilter(query: string): void {
+            component["applyFilter"](query);
+        }
+
+        it("should create", async () => {
+            await setup();
+            expect(component).toBeTruthy();
+        });
+
+        describe("applyFilter", () => {
+            beforeEach(async () => {
+                await setup();
+            });
+
+            it("includes all non-selected contacts when query is empty", () => {
+                const a = makeContact({ ContactID: 1, DisplayName: "A" });
+                const b = makeContact({ ContactID: 2, DisplayName: "B" });
+                fixture.componentRef.setInput("contacts", [a, b]);
+                component.selected.set([]);
+                applyFilter("");
+                expect(component.filteredContacts().map((c) => c.ContactID).sort()).toEqual([1, 2]);
+            });
+
+            it("excludes contacts already in selected", () => {
+                const a = makeContact({ ContactID: 1 });
+                const b = makeContact({ ContactID: 2 });
+                fixture.componentRef.setInput("contacts", [a, b]);
+                component.selected.set([a]);
+                applyFilter("");
+                expect(component.filteredContacts().map((c) => c.ContactID)).toEqual([2]);
+            });
+
+            it("matches DisplayName case-insensitively", () => {
+                fixture.componentRef.setInput("contacts", [
+                    makeContact({ ContactID: 1, DisplayName: "Alice Smith", Email: "a@x.com" }),
+                    makeContact({ ContactID: 2, DisplayName: "Bob", Email: "b@x.com" }),
+                ]);
+                component.selected.set([]);
+                applyFilter("ALI");
+                expect(component.filteredContacts().map((c) => c.ContactID)).toEqual([1]);
+            });
+
+            it("matches Email case-insensitively", () => {
+                fixture.componentRef.setInput("contacts", [
+                    makeContact({ ContactID: 1, DisplayName: "A", Email: "findme@corp.org" }),
+                    makeContact({ ContactID: 2, DisplayName: "B", Email: "other@x.com" }),
+                ]);
+                component.selected.set([]);
+                applyFilter("FINDME");
+                expect(component.filteredContacts().map((c) => c.ContactID)).toEqual([1]);
+            });
+
+            it("sets showDropdown false when no matches", () => {
+                fixture.componentRef.setInput("contacts", [makeContact({ ContactID: 1, DisplayName: "Only" })]);
+                component.selected.set([]);
+                applyFilter("zzznomatch");
+                expect(component.filteredContacts().length).toBe(0);
+                expect(component.showDropdown()).toBe(false);
+            });
+
+            it("caps filtered results at 50", () => {
+                const many: ContactForPicklist[] = [];
+                for (let i = 0; i < 60; i++) {
+                    many.push(makeContact({ ContactID: i + 1, DisplayName: `User ${i}` }));
+                }
+                fixture.componentRef.setInput("contacts", many);
+                component.selected.set([]);
+                applyFilter("");
+                expect(component.filteredContacts().length).toBe(50);
+            });
+        });
+
+        describe("selectContact / removeContact", () => {
+            beforeEach(async () => {
+                await setup();
+            });
+
+            it("selectContact appends contact, clears query and filtered list, closes dropdown", () => {
+                const c = makeContact({ ContactID: 7 });
+                fixture.componentRef.setInput("contacts", [c]);
+                component.selected.set([]);
+                component.query.set("typed");
+                component.filteredContacts.set([c]);
+                component.showDropdown.set(true);
+
+                component["selectContact"](c);
+
+                expect(component.selected()).toEqual([c]);
+                expect(component.query()).toBe("");
+                expect(component.filteredContacts()).toEqual([]);
+                expect(component.showDropdown()).toBe(false);
+            });
+
+            it("removeContact drops by ContactID", () => {
+                const a = makeContact({ ContactID: 1 });
+                const b = makeContact({ ContactID: 2 });
+                component.selected.set([a, b]);
+                component["removeContact"](a);
+                expect(component.selected().map((x) => x.ContactID)).toEqual([2]);
+            });
+        });
+
+        describe("onQueryChange (debounced)", () => {
+            beforeEach(async () => {
+                await setup();
+            });
+
+            it("debounces then applies filter", async () => {
+                fixture.componentRef.setInput("contacts", [
+                    makeContact({ ContactID: 1, DisplayName: "Alice" }),
+                    makeContact({ ContactID: 2, DisplayName: "Bob" }),
+                ]);
+                component.selected.set([]);
+                component["onQueryChange"]("bob");
+                expect(component.filteredContacts().length).toBe(0);
+                await vi.advanceTimersByTimeAsync(200);
+                expect(component.filteredContacts().map((c) => c.ContactID)).toEqual([2]);
+            });
+        });
+
+        describe("onChevronToggle", () => {
+            beforeEach(async () => {
+                await setup();
+            });
+
+            it("closes dropdown when filter yields no results", () => {
+                fixture.componentRef.setInput("contacts", [makeContact({ ContactID: 1, DisplayName: "X" })]);
+                component.selected.set([]);
+                component.query.set("nomatchxyz");
+                component.showDropdown.set(true);
+                component["onChevronToggle"]();
+                expect(component.showDropdown()).toBe(false);
+            });
+
+            it("toggles dropdown when results exist", () => {
+                fixture.componentRef.setInput("contacts", [makeContact({ ContactID: 1, DisplayName: "Pat" })]);
+                component.selected.set([]);
+                component.query.set("pat");
+                component.showDropdown.set(false);
+                component["onChevronToggle"]();
+                expect(component.filteredContacts().length).toBeGreaterThan(0);
+                expect(component.showDropdown()).toBe(true);
+            });
+        });
+
+        describe("onSearchClick", () => {
+            beforeEach(async () => {
+                await setup();
+            });
+
+            it("closes the dropdown when invoked", () => {
+                component.showDropdown.set(true);
+                component["onSearchClick"]();
+                expect(component.showDropdown()).toBe(false);
+            });
+
+            it("emits searchIconClicked with the inner button element when the view child is present", () => {
+                const anchor = document.createElement("button");
+                component["_searchActionBtn"] = {
+                    element: { nativeElement: anchor },
+                } as ModusButtonComponent;
+                let emitted: HTMLElement | undefined;
+                component.searchIconClicked.subscribe((el) => {
+                    emitted = el;
+                });
+                component["onSearchClick"]();
+                expect(emitted).toBe(anchor);
+            });
+
+            it("does not emit searchIconClicked when no view child is available", () => {
+                let count = 0;
+                component.searchIconClicked.subscribe(() => {
+                    count++;
+                });
+                component["onSearchClick"]();
+                expect(count).toBe(0);
+            });
+        });
+    });
+});
diff --git a/Core/Web Layer/WebUI/ps-ng/src/app/shared/controls/contact-input/contact-input.component.ts b/Core/Web Layer/WebUI/ps-ng/src/app/shared/controls/contact-input/contact-input.component.ts
